INSERT INTO `conversations` VALUES (852, '2026-03-08 14:24:03.903274', '刑法基本原则是什么？', '2026-03-08 14:24:03.903274', 1);
INSERT INTO `conversations_seq` VALUES (951);
INSERT INTO `documents` VALUES (402, '中华人民共和国民法典合同编与消费者权益保护法\r\n重要条款汇编\r\n\r\n第一部分 民法典合同编\r\n\r\n第一章 通则\r\n\r\n第四百六十三条 本编调整因合同产生的民事关系。\r\n\r\n第四百六十四条 合同是民事主体之间设立、变更、终止民事法律关系的协议。婚姻、收养、监护等有关身份关系的协议，适用有关该身份关系的法律规定；没有规定的，可以根据其性质参照适用本编规定。\r\n\r\n第四百六十五条 依法成立的合同，受法律保护。依法成立的合同，仅对当事人具有法律约束力，但是法律另有规定的除外。\r\n\r\n第二章 合同的订立\r\n\r\n第四百七十一条 当事人订立合同，可以采取要约、承诺方式或者其他方式。\r\n\r\n第四百七十二条 要约是希望与他人订立合同的意思表示，该意思表示应当符合下列条件：（一）内容具体确定；（二）表明经受要约人承诺，要约人即受该意思表示约束。\r\n\r\n第四百七十九条 承诺是受要约人同意要约的意思表示。\r\n\r\n第四百九十条 当事人采用合同书形式订立合同的，自当事人均签名、盖章或者按指印时合同成立。在签名、盖章或者按指印之前，当事人一方已经履行主要义务，对方接受时，该合同成立。\r\n\r\n第四百九十六条 格式条款是当事人为了重复使用而预先拟定，并在订立合同时未与对方协商的条款。采用格式条款订立合同的，提供格式条款的一方应当遵循公平原则确定当事人之间的权利和义务，并采取合理的方式提示对方注意免除或者减轻其责任等与对方有重大利害关系的条款，按照对方的要求，对该条款予以说明。\r\n\r\n第四百九十七条 有下列情形之一的，该格式条款无效：（一）具有本法第一编第六章第三节和本法第五百零六条规定的无效情形；（二）提供格式条款一方不合理地免除或者减轻其责任、加重对方责任、限制对方主要权利；（三）提供格式条款一方排除对方主要权利。\r\n\r\n第三章 合同的效力\r\n\r\n第五百零二条 依法成立的合同，自成立时生效，但是法律另有规定或者当事人另有约定的除外。\r\n\r\n第五百零六条 合同中的下列免责条款无效：（一）造成对方人身损害的；（二）因故意或者重大过失造成对方财产损失的。\r\n\r\n第四章 合同的履行\r\n\r\n第五百零九条 当事人应当按照约定全面履行自己的义务。当事人应当遵循诚信原则，根据合同的性质、目的和交易习惯履行通知、协助、保密等义务。\r\n\r\n第五百一十条 合同生效后，当事人就质量、价款或者报酬、履行地点等内容没有约定或者约定不明确的，可以协议补充；不能达成补充协议的，按照合同相关条款或者交易习惯确定。\r\n\r\n第五章 合同的变更和转让\r\n\r\n第五百四十三条 当事人协商一致，可以变更合同。\r\n\r\n第五百四十五条 债权人可以将债权的全部或者部分转让给第三人，但是有下列情形之一的除外：（一）根据债权性质不得转让；（二）按照当事人约定不得转让；（三）依照法律规定不得转让。\r\n\r\n第六章 合同的权利义务终止\r\n\r\n第五百五十七条 有下列情形之一的，债权债务终止：（一）债务已经履行；（二）债务相互抵销；（三）债务人依法将标的物提存；（四）债权人免除债务；（五）债权债务同归于一人；（六）法律规定或者当事人约定终止的其他情形。\r\n\r\n第五百六十二条 当事人协商一致，可以解除合同。当事人可以约定一方解除合同的事由。解除合同的事由发生时，解除权人可以解除合同。\r\n\r\n第五百六十三条 有下列情形之一的，当事人可以解除合同：（一）因不可抗力致使不能实现合同目的；（二）在履行期限届满前，当事人一方明确表示或者以自己的行为表明不履行主要债务；（三）当事人一方迟延履行主要债务，经催告后在合理期限内仍未履行；（四）当事人一方迟延履行债务或者有其他违约行为致使不能实现合同目的；（五）法律规定的其他情形。\r\n\r\n第七章 违约责任\r\n\r\n第五百七十七条 当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担继续履行、采取补救措施或者赔偿损失等违约责任。\r\n\r\n第五百七十八条 当事人一方明确表示或者以自己的行为表明不履行合同义务的，对方可以在履行期限届满前请求其承担违约责任。\r\n\r\n第五百八十四条 当事人一方不履行合同义务或者履行合同义务不符合约定，造成对方损失的，损失赔偿额应当相当于因违约所造成的损失，包括合同履行后可以获得的利益；但是，不得超过违约一方订立合同时预见到或者应当预见到的因违约可能造成的损失。\r\n\r\n第五百八十五条 当事人可以约定一方违约时应当根据违约情况向对方支付一定数额的违约金，也可以约定因违约产生的损失赔偿额的计算方法。约定的违约金低于造成的损失的，人民法院或者仲裁机构可以根据当事人的请求予以增加；约定的违约金过分高于造成的损失的，人民法院或者仲裁机构可以根据当事人的请求予以适当减少。\r\n\r\n第五百九十条 当事人一方因不可抗力不能履行合同的，根据不可抗力的影响，部分或者全部免除责任，但是法律另有规定的除外。因不可抗力不能履行合同的，应当及时通知对方，以减轻可能给对方造成的损失，并应当在合理期限内提供证明。\r\n\r\n第二部分 消费者权益保护法\r\n\r\n第一章 总则\r\n\r\n第一条 为保护消费者的合法权益，维护社会经济秩序，促进社会主义市场经济健康发展，制定本法。\r\n\r\n第二条 消费者为生活消费需要购买、使用商品或者接受服务，其权益受本法保护；本法未作规定的，受其他有关法律、法规保护。\r\n\r\n第二章 消费者的权利\r\n\r\n第七条 消费者在购买、使用商品和接受服务时享有人身、财产安全不受损害的权利。消费者有权要求经营者提供的商品和服务，符合保障人身、财产安全的要求。\r\n\r\n第八条 消费者享有知悉其购买、使用的商品或者接受的服务的真实情况的权利。消费者有权根据商品或者服务的不同情况，要求经营者提供商品的价格、产地、生产者、用途、性能、规格、等级、主要成份、生产日期、有效期限、检验合格证明、使用方法说明书、售后服务，或者服务的内容、规格、费用等有关情况。\r\n\r\n第九条 消费者享有自主选择商品或者服务的权利。消费者有权自主选择提供商品或者服务的经营者，自主选择商品品种或者服务方式，自主决定购买或者不购买任何一种商品、接受或者不接受任何一项服务。\r\n\r\n第十条 消费者享有公平交易的权利。消费者在购买商品或者接受服务时，有权获得质量保障、价格合理、计量正确等公平交易条件，有权拒绝经营者的强制交易行为。\r\n\r\n第十一条 消费者因购买、使用商品或者接受服务受到人身、财产损害的，享有依法获得赔偿的权利。\r\n\r\n第三章 经营者的义务\r\n\r\n第十六条 经营者向消费者提供商品或者服务，应当依照本法和其他有关法律、法规的规定履行义务。经营者和消费者有约定的，应当按照约定履行义务，但双方的约定不得违背法律、法规的规定。\r\n\r\n第十八条 经营者应当保证其提供的商品或者服务符合保障人身、财产安全的要求。对可能危及人身、财产安全的商品和服务，应当向消费者作出真实的说明和明确的警示，并说明和标明正确使用商品或者接受服务的方法以及防止危害发生的方法。\r\n\r\n第二十条 经营者向消费者提供有关商品或者服务的质量、性能、用途、有效期限等信息，应当真实、全面，不得作虚假或者引人误解的宣传。\r\n\r\n第二十三条 经营者应当保证在正常使用商品或者接受服务的情况下其提供的商品或者服务应当具有的质量、性能、用途和有效期限；但消费者在购买该商品或者接受该服务前已经知道其存在瑕疵，且存在该瑕疵不违反法律强制性规定的除外。\r\n\r\n第二十五条 经营者采用网络、电视、电话、邮购等方式销售商品，消费者有权自收到商品之日起七日内退货，且无需说明理由，但下列商品除外：（一）消费者定作的；（二）鲜活易腐的；（三）在线下载或者消费者拆封的音像制品、计算机软件等数字化商品；（四）交付的报纸、期刊。\r\n\r\n第四章 国家对消费者合法权益的保护\r\n\r\n第三十九条 消费者和经营者发生消费者权益争议的，可以通过下列途径解决：（一）与经营者协商和解；（二）请求消费者协会或者依法成立的其他调解组织调解；（三）向有关行政部门投诉；（四）根据与经营者达成的仲裁协议提请仲裁机构仲裁；（五）向人民法院提起诉讼。\r\n\r\n第五章 法律责任\r\n\r\n第五十五条 经营者提供商品或者服务有欺诈行为的，应当按照消费者的要求增加赔偿其受到的损失，增加赔偿的金额为消费者购买商品的价款或者接受服务的费用的三倍；增加赔偿的金额不足五百元的，为五百元。法律另有规定的，依照其规定。\r\n\r\n经营者明知商品或者服务存在缺陷，仍然向消费者提供，造成消费者或者其他受害人死亡或者健康严重损害的，受害人有权要求经营者依照本法第四十九条、第五十一条等法律规定赔偿损失，并有权要求所受损失二倍以下的惩罚性赔偿。\r\n', '2026-03-08 14:18:29.329027', '.\\data\\uploads\\2fb8c8a9-efc3-4167-890c-abefb7c193b3.txt', 10172, '.txt', '2fb8c8a9-efc3-4167-890c-abefb7c193b3.txt', 28, '中华人民共和国合同法与消费者权益保护法.txt', 28, 'indexed', '2026-03-08 14:22:26.508402', 'rule');
INSERT INTO `documents` VALUES (403, '中华人民共和国民法典婚姻家庭编与继承编\r\n重要条款汇编\r\n\r\n第一部分 婚姻家庭编\r\n\r\n第一章 一般规定\r\n\r\n第一千零四十条 本编调整因婚姻家庭产生的民事关系。\r\n\r\n第一千零四十一条 婚姻家庭受国家保护。实行婚姻自由、一夫一妻、男女平等的婚姻制度。保护妇女、未成年人、老年人、残疾人的合法权益。\r\n\r\n第一千零四十二条 禁止包办、买卖婚姻和其他干涉婚姻自由的行为。禁止借婚姻索取财物。禁止重婚。禁止有配偶者与他人同居。禁止家庭暴力。禁止家庭成员间的虐待和遗弃。\r\n\r\n第二章 结婚\r\n\r\n第一千零四十六条 结婚应当男女双方完全自愿，禁止任何一方对另一方加以强迫，禁止任何组织或者个人加以干涉。\r\n\r\n第一千零四十七条 结婚年龄，男不得早于二十二周岁，女不得早于二十周岁。\r\n\r\n第一千零四十八条 直系血亲或者三代以内的旁系血亲禁止结婚。\r\n\r\n第一千零四十九条 要求结婚的男女双方应当亲自到婚姻登记机关申请结婚登记。符合本法规定的，予以登记，发给结婚证。完成结婚登记，即确立婚姻关系。未办理结婚登记的，应当补办登记。\r\n\r\n第一千零五十一条 有下列情形之一的，婚姻无效：（一）重婚；（二）有禁止结婚的亲属关系；（三）未到法定婚龄。\r\n\r\n第三章 家庭关系\r\n\r\n第一千零五十五条 夫妻在婚姻家庭中地位平等。\r\n\r\n第一千零五十八条 夫妻双方平等享有对未成年子女抚养、教育和保护的权利，共同承担对未成年子女抚养、教育和保护的义务。\r\n\r\n第一千零六十二条 夫妻在婚姻关系存续期间所得的下列财产，为夫妻的共同财产，归夫妻共同所有：（一）工资、奖金、劳务报酬；（二）生产、经营、投资的收益；（三）知识产权的收益；（四）继承或者受赠的财产，但是本法第一千零六十三条第三项规定的除外；（五）其他应当归共同所有的财产。夫妻对共同财产，有平等的处理权。\r\n\r\n第一千零六十三条 下列财产为夫妻一方的个人财产：（一）一方的婚前财产；（二）一方因受到人身损害获得的赔偿或者补偿；（三）遗嘱或者赠与合同中确定只归一方的财产；（四）一方专用的生活用品；（五）其他应当归一方的财产。\r\n\r\n第一千零六十七条 父母不履行抚养义务的，未成年子女或者不能独立生活的成年子女，有要求父母给付抚养费的权利。成年子女不履行赡养义务的，缺乏劳动能力或者生活困难的父母，有要求成年子女给付赡养费的权利。\r\n\r\n第四章 离婚\r\n\r\n第一千零七十六条 夫妻双方自愿离婚的，应当签订书面离婚协议，并亲自到婚姻登记机关申请离婚登记。离婚协议应当载明双方自愿离婚的意思表示和对子女抚养、财产以及债务处理等事项协商一致的意见。\r\n\r\n第一千零七十七条 自婚姻登记机关收到离婚登记申请之日起三十日内，任何一方不愿意离婚的，可以向婚姻登记机关撤回离婚登记申请。前款规定期限届满后三十日内，双方应当亲自到婚姻登记机关申请发给离婚证；未申请的，视为撤回离婚登记申请。\r\n\r\n第一千零七十九条 夫妻一方要求离婚的，可以由有关组织进行调解或者直接向人民法院提起离婚诉讼。人民法院审理离婚案件，应当进行调解；如果感情确已破裂，调解无效的，应当准予离婚。有下列情形之一，调解无效的，应当准予离婚：（一）重婚或者与他人同居；（二）实施家庭暴力或者虐待、遗弃家庭成员；（三）有赌博、吸毒等恶习屡教不改；（四）因感情不和分居满二年；（五）其他导致夫妻感情破裂的情形。\r\n\r\n第一千零八十四条 父母与子女间的关系，不因父母离婚而消除。离婚后，子女无论由父或者母直接抚养，仍是父母双方的子女。离婚后，父母对于子女仍有抚养、教育、保护的权利和义务。离婚后，不满两周岁的子女，以由母亲直接抚养为原则。已满两周岁的子女，父母双方对抚养问题协议不成的，由人民法院根据双方的具体情况，按照最有利于未成年子女的原则判决。子女已满八周岁的，应当尊重其真实意愿。\r\n\r\n第一千零八十七条 离婚时，夫妻的共同财产由双方协议处理；协议不成的，由人民法院根据财产的具体情况，按照照顾子女、女方和无过错方权益的原则判决。\r\n\r\n第一千零九十一条 有下列情形之一，导致离婚的，无过错方有权请求损害赔偿：（一）重婚；（二）与他人同居；（三）实施家庭暴力；（四）虐待、遗弃家庭成员；（五）有其他重大过错。\r\n\r\n第二部分 继承编\r\n\r\n第一章 一般规定\r\n\r\n第一千一百一十九条 本编调整因继承产生的民事关系。\r\n\r\n第一千一百二十条 国家保护自然人的继承权。\r\n\r\n第一千一百二十一条 继承从被继承人死亡时开始。相互有继承关系的数人在同一事件中死亡，难以确定死亡时间的，推定没有其他继承人的人先死亡。都有其他继承人，辈份不同的，推定长辈先死亡；辈份相同的，推定同时死亡，相互不发生继承。\r\n\r\n第一千一百二十二条 遗产是自然人死亡时遗留的个人合法财产。依照法律规定或者根据其性质不得继承的遗产，不得继承。\r\n\r\n第二章 法定继承\r\n\r\n第一千一百二十六条 继承权男女平等。\r\n\r\n第一千一百二十七条 遗产按照下列顺序继承：（一）第一顺序：配偶、子女、父母；（二）第二顺序：兄弟姐妹、祖父母、外祖父母。继承开始后，由第一顺序继承人继承，第二顺序继承人不继承；没有第一顺序继承人继承的，由第二顺序继承人继承。\r\n\r\n第一千一百二十八条 被继承人的子女先于被继承人死亡的，由被继承人的子女的直系晚辈血亲代位继承。被继承人的兄弟姐妹先于被继承人死亡的，由被继承人的兄弟姐妹的子女代位继承。代位继承人一般只能继承被代位继承人有权继承的遗产份额。\r\n\r\n第一千一百三十条 同一顺序继承人继承遗产的份额，一般应当均等。对生活有特殊困难又缺乏劳动能力的继承人，分配遗产时，应当予以照顾。对被继承人尽了主要扶养义务或者与被继承人共同生活的继承人，分配遗产时，可以多分。有扶养能力和有扶养条件的继承人，不尽扶养义务的，分配遗产时，应当不分或者少分。\r\n\r\n第三章 遗嘱继承和遗赠\r\n\r\n第一千一百三十三条 自然人可以依照本法规定立遗嘱处分个人财产，并可以指定遗嘱执行人。自然人可以立遗嘱将个人财产指定由法定继承人中的一人或者数人继承。自然人可以立遗嘱将个人财产赠与国家、集体或者法定继承人以外的组织、个人。\r\n\r\n第一千一百三十四条 自书遗嘱由遗嘱人亲笔书写，签名，注明年、月、日。\r\n\r\n第一千一百三十五条 代书遗嘱应当有两个以上见证人在场见证，由其中一人代书，并由遗嘱人、代书人和其他见证人签名，注明年、月、日。\r\n\r\n第一千一百三十六条 打印遗嘱应当有两个以上见证人在场见证。遗嘱人和见证人应当在遗嘱每一页签名，注明年、月、日。\r\n\r\n第一千一百三十七条 以录音录像形式立的遗嘱，应当有两个以上见证人在场见证。遗嘱人和见证人应当在录音录像中记录其姓名或者肖像，以及年、月、日。\r\n\r\n第一千一百四十二条 遗嘱人可以撤回、变更自己所立的遗嘱。立遗嘱后，遗嘱人实施与遗嘱内容相反的民事法律行为的，视为对遗嘱相关内容的撤回。立有数份遗嘱，内容相抵触的，以最后的遗嘱为准。\r\n\r\n第一千一百四十一条 遗嘱应当为缺乏劳动能力又没有生活来源的继承人保留必要的遗产份额。\r\n', '2026-03-08 14:18:32.750383', '.\\data\\uploads\\3953a130-5782-4655-92be-d749892aa201.txt', 8331, '.txt', '3953a130-5782-4655-92be-d749892aa201.txt', 14, '中华人民共和国婚姻法与继承法.txt', 14, 'indexed', '2026-03-08 14:22:24.585573', 'semantic');
INSERT INTO `documents` VALUES (404, '中华人民共和国道路交通安全法与治安管理处罚法\r\n重要条款汇编\r\n\r\n第一部分 道路交通安全法\r\n\r\n第一章 总则\r\n\r\n第一条 为了维护道路交通秩序，预防和减少交通事故，保护人身安全，保护公民、法人和其他组织的财产安全及其他合法权益，提高通行效率，制定本法。\r\n\r\n第二条 中华人民共和国境内的车辆驾驶人、行人、乘车人以及与道路交通活动有关的单位和个人，都应当遵守本法。\r\n\r\n第二章 车辆和驾驶人\r\n\r\n第八条 国家对机动车实行登记制度。机动车经公安机关交通管理部门登记后，方可上道路行驶。尚未登记的机动车，需要临时上道路行驶的，应当取得临时通行牌证。\r\n\r\n第十九条 驾驶机动车，应当依法取得机动车驾驶证。申请机动车驾驶证，应当符合国务院公安部门规定的驾驶许可条件；经考试合格后，由公安机关交通管理部门发给相应类别的机动车驾驶证。\r\n\r\n第二十二条 机动车驾驶人应当遵守道路交通安全法律、法规的规定，按照操作规范安全驾驶、文明驾驶。饮酒、服用国家管制的精神药品或者麻醉药品，或者患有妨碍安全驾驶机动车的疾病，或者过度疲劳影响安全驾驶的，不得驾驶机动车。\r\n\r\n第三章 道路通行条件\r\n\r\n第二十五条 全国实行统一的道路交通信号。交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥。\r\n\r\n第四章 道路通行规定\r\n\r\n第四十二条 机动车上道路行驶，不得超过限速标志标明的最高时速。在没有限速标志的路段，应当保持安全车速。\r\n\r\n第四十三条 同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。\r\n\r\n第四十七条 机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行。机动车行经没有交通信号的道路时，遇行人横过道路，应当避让。\r\n\r\n第五十一条 机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。\r\n\r\n第七十条 在道路上发生交通事故，车辆驾驶人应当立即停车，保护现场；造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门。\r\n\r\n第七十六条 机动车发生交通事故造成人身伤亡、财产损失的，由保险公司在机动车第三者责任强制保险责任限额范围内予以赔偿；不足的部分，按照下列规定承担赔偿责任：（一）机动车之间发生交通事故的，由有过错的一方承担赔偿责任；双方都有过错的，按照各自过错的比例分担责任。（二）机动车与非机动车驾驶人、行人之间发生交通事故，非机动车驾驶人、行人没有过错的，由机动车一方承担赔偿责任；有证据证明非机动车驾驶人、行人有过错的，根据过错程度适当减轻机动车一方的赔偿责任；机动车一方没有过错的，承担不超过百分之十的赔偿责任。\r\n\r\n第九十一条 饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车的，处十日以下拘留，并处一千元以上二千元以下罚款，吊销机动车驾驶证。醉酒驾驶机动车的，由公安机关交通管理部门约束至酒醒，吊销机动车驾驶证，依法追究刑事责任；五年内不得重新取得机动车驾驶证。\r\n\r\n第九十九条 有下列行为之一的，由公安机关交通管理部门处二百元以上二千元以下罚款：（一）未取得机动车驾驶证、机动车驾驶证被吊销或者机动车驾驶证被暂扣期间驾驶机动车的；（二）将机动车交由未取得机动车驾驶证或者机动车驾驶证被吊销、暂扣的人驾驶的；（三）造成交通事故后逃逸，尚不构成犯罪的；（四）机动车行驶超过规定时速百分之五十的。\r\n\r\n第二部分 治安管理处罚法\r\n\r\n第一章 总则\r\n\r\n第一条 为维护社会治安秩序，保障公共安全，保护公民、法人和其他组织的合法权益，规范和保障公安机关及其人民警察依法履行治安管理职责，制定本法。\r\n\r\n第二条 扰乱公共秩序，妨害公共安全，侵犯人身权利、财产权利，妨害社会管理，具有社会危害性，依照《中华人民共和国刑法》的规定构成犯罪的，依法追究刑事责任；尚不够刑事处罚的，由公安机关依照本法给予治安管理处罚。\r\n\r\n第二章 处罚的种类和适用\r\n\r\n第十条 治安管理处罚的种类分为：（一）警告；（二）罚款；（三）行政拘留；（四）吊销公安机关发放的许可证。对违反治安管理的外国人，可以附加适用限期出境或者驱逐出境。\r\n\r\n第十二条 已满十四周岁不满十八周岁的人违反治安管理的，从轻或者减轻处罚；不满十四周岁的人违反治安管理的，不予处罚，但是应当责令其监护人严加管教。\r\n\r\n第十九条 违反治安管理有下列情形之一的，减轻处罚或者不予处罚：（一）情节特别轻微的；（二）主动消除或者减轻违法后果，并取得被侵害人谅解的；（三）出于他人胁迫或者诱骗的；（四）主动投案，向公安机关如实陈述自己的违法行为的；（五）有立功表现的。\r\n\r\n第三章 违反治安管理的行为和处罚\r\n\r\n第二十三条 有下列行为之一的，处警告或者二百元以下罚款；情节较重的，处五日以上十日以下拘留，可以并处五百元以下罚款：（一）扰乱机关、团体、企业、事业单位秩序，致使工作、生产、营业、医疗、教学、科研不能正常进行，尚未造成严重损失的；（二）扰乱车站、港口、码头、机场、商场、公园、展览馆或者其他公共场所秩序的；（三）扰乱公共汽车、电车、火车、船舶、航空器或者其他公共交通工具上的秩序的。\r\n\r\n第四十二条 有下列行为之一的，处五日以下拘留或者五百元以下罚款；情节较重的，处五日以上十日以下拘留，可以并处五百元以下罚款：（一）写恐吓信或者以其他方法威胁他人人身安全的；（二）公然侮辱他人或者捏造事实诽谤他人的；（三）捏造事实诬告陷害他人，企图使他人受到刑事追究或者受到治安管理处罚的；（四）对证人及其近亲属进行威胁、侮辱、殴打或者打击报复的；（五）多次发送淫秽、侮辱、恐吓或者其他信息，干扰他人正常生活的；（六）偷窥、偷拍、窃听、散布他人隐私的。\r\n\r\n第四十三条 殴打他人的，或者故意伤害他人身体的，处五日以上十日以下拘留，并处二百元以上五百元以下罚款；情节较轻的，处五日以下拘留或者五百元以下罚款。有下列情形之一的，处十日以上十五日以下拘留，并处五百元以上一千元以下罚款：（一）结伙殴打、伤害他人的；（二）殴打、伤害残疾人、孕妇、不满十四周岁的人或者六十周岁以上的人的；（三）多次殴打、伤害他人或者一次殴打、伤害多人的。\r\n\r\n第四十九条 盗窃、诈骗、哄抢、抢夺、敲诈勒索或者故意损毁公私财物的，处五日以上十日以下拘留，可以并处五百元以下罚款；情节较重的，处十日以上十五日以下拘留，可以并处一千元以下罚款。\r\n\r\n第七十二条 有下列行为之一的，处十日以上十五日以下拘留，可以并处二千元以下罚款；情节较轻的，处五日以下拘留或者五百元以下罚款：（一）非法持有鸦片不满二百克、海洛因或者甲基苯丙胺不满十克或者其他少量毒品的；（二）向他人提供毒品的；（三）吸食、注射毒品的；（四）胁迫、欺骗医务人员开具麻醉药品、精神药品的。\r\n', '2026-03-08 14:18:36.471382', '.\\data\\uploads\\c9c7daed-fddd-4cbf-8ce4-7961eb61b14c.txt', 8233, '.txt', 'c9c7daed-fddd-4cbf-8ce4-7961eb61b14c.txt', 23, '中华人民共和国交通安全与治安管理法.txt', 23, 'indexed', '2026-03-08 14:22:23.946423', 'paragraph');
INSERT INTO `documents` VALUES (405, '中华人民共和国劳动法与劳动合同法\r\n重要条款汇编\r\n\r\n第一部分 劳动法\r\n\r\n第一章 总则\r\n\r\n第一条 为了保护劳动者的合法权益，调整劳动关系，建立和维护适应社会主义市场经济的劳动制度，促进经济发展和社会进步，根据宪法，制定本法。\r\n\r\n第二条 在中华人民共和国境内的企业、个体经济组织和与之形成劳动关系的劳动者，适用本法。国家机关、事业组织、社会团体和与之建立劳动合同关系的劳动者，依照本法执行。\r\n\r\n第三条 劳动者享有平等就业和选择职业的权利、取得劳动报酬的权利、休息休假的权利、获得劳动安全卫生保护的权利、接受职业技能培训的权利、享受社会保险和福利的权利、提请劳动争议处理的权利以及法律规定的其他劳动权利。\r\n\r\n第二章 劳动合同和集体合同\r\n\r\n第十六条 劳动合同是劳动者与用人单位确立劳动关系、明确双方权利和义务的协议。建立劳动关系应当订立劳动合同。\r\n\r\n第十七条 订立和变更劳动合同，应当遵循平等自愿、协商一致的原则，不得违反法律、行政法规的规定。劳动合同依法订立即具有法律约束力，当事人必须履行劳动合同规定的义务。\r\n\r\n第十九条 劳动合同应当以书面形式订立，并具备以下条款：（一）劳动合同期限；（二）工作内容；（三）劳动保护和劳动条件；（四）劳动报酬；（五）劳动纪律；（六）劳动合同终止的条件；（七）违反劳动合同的责任。\r\n\r\n第二十五条 劳动者有下列情形之一的，用人单位可以解除劳动合同：（一）在试用期间被证明不符合录用条件的；（二）严重违反劳动纪律或者用人单位规章制度的；（三）严重失职，营私舞弊，对用人单位利益造成重大损害的；（四）被依法追究刑事责任的。\r\n\r\n第二十六条 有下列情形之一的，用人单位可以解除劳动合同，但是应当提前三十日以书面形式通知劳动者本人：（一）劳动者患病或者非因工负伤，医疗期满后，不能从事原工作也不能从事由用人单位另行安排的工作的；（二）劳动者不能胜任工作，经过培训或者调整工作岗位，仍不能胜任工作的；（三）劳动合同订立时所依据的客观情况发生重大变化，致使原劳动合同无法履行，经当事人协商不能就变更劳动合同达成协议的。\r\n\r\n第二十九条 劳动者有下列情形之一的，用人单位不得依据本法第二十六条、第二十七条的规定解除劳动合同：（一）患职业病或者因工负伤并被确认丧失或者部分丧失劳动能力的；（二）患病或者负伤，在规定的医疗期内的；（三）女职工在孕期、产期、哺乳期内的；（四）法律、行政法规规定的其他情形。\r\n\r\n第三章 工资\r\n\r\n第四十六条 工资分配应当遵循按劳分配原则，实行同工同酬。工资水平在经济发展的基础上逐步提高。国家对工资总量实行宏观调控。\r\n\r\n第四十八条 国家实行最低工资保障制度。最低工资的具体标准由省、自治区、直辖市人民政府规定，报国务院备案。用人单位支付劳动者的工资不得低于当地最低工资标准。\r\n\r\n第五十条 工资应当以货币形式按月支付给劳动者本人。不得克扣或者无故拖欠劳动者的工资。\r\n\r\n第四章 工作时间和休息休假\r\n\r\n第三十六条 国家实行劳动者每日工作时间不超过八小时、平均每周工作时间不超过四十四小时的工时制度。\r\n\r\n第三十八条 用人单位应当保证劳动者每周至少休息一日。\r\n\r\n第四十一条 用人单位由于生产经营需要，经与工会和劳动者协商后可以延长工作时间，一般每日不得超过一小时；因特殊原因需要延长工作时间的，在保障劳动者身体健康的条件下延长工作时间每日不得超过三小时，但是每月不得超过三十六小时。\r\n\r\n第四十四条 有下列情形之一的，用人单位应当按照下列标准支付高于劳动者正常工作时间工资的工资报酬：（一）安排劳动者延长工作时间的，支付不低于工资的百分之一百五十的工资报酬；（二）休息日安排劳动者工作又不能安排补休的，支付不低于工资的百分之二百的工资报酬；（三）法定休假日安排劳动者工作的，支付不低于工资的百分之三百的工资报酬。\r\n\r\n第二部分 劳动合同法\r\n\r\n第一章 总则\r\n\r\n第一条 为了完善劳动合同制度，明确劳动合同双方当事人的权利和义务，保护劳动者的合法权益，构建和发展和谐稳定的劳动关系，制定本法。\r\n\r\n第二条 中华人民共和国境内的企业、个体经济组织、民办非企业单位等组织与劳动者建立劳动关系，订立、履行、变更、解除或者终止劳动合同，适用本法。\r\n\r\n第二章 劳动合同的订立\r\n\r\n第七条 用人单位自用工之日起即与劳动者建立劳动关系。用人单位应当建立职工名册备查。\r\n\r\n第十条 建立劳动关系，应当订立书面劳动合同。已建立劳动关系，未同时订立书面劳动合同的，应当自用工之日起一个月内订立书面劳动合同。\r\n\r\n第十四条 无固定期限劳动合同，是指用人单位与劳动者约定无确定终止时间的劳动合同。有下列情形之一，劳动者提出或者同意续订、订立劳动合同的，除劳动者提出订立固定期限劳动合同外，应当订立无固定期限劳动合同：（一）劳动者在该用人单位连续工作满十年的；（二）用人单位初次实行劳动合同制度或者国有企业改制重新订立劳动合同时，劳动者在该用人单位连续工作满十年且距法定退休年龄不足十年的；（三）连续订立二次固定期限劳动合同，且劳动者没有本法第三十九条和第四十条第一项、第二项规定的情形，续订劳动合同的。\r\n\r\n第十九条 劳动合同期限三个月以上不满一年的，试用期不得超过一个月；劳动合同期限一年以上不满三年的，试用期不得超过二个月；三年以上固定期限和无固定期限的劳动合同，试用期不得超过六个月。同一用人单位与同一劳动者只能约定一次试用期。\r\n\r\n第二十条 劳动者在试用期的工资不得低于本单位相同岗位最低档工资或者劳动合同约定工资的百分之八十，并不得低于用人单位所在地的最低工资标准。\r\n\r\n第二十二条 用人单位为劳动者提供专项培训费用，对其进行专业技术培训的，可以与该劳动者订立协议，约定服务期。劳动者违反服务期约定的，应当按照约定向用人单位支付违约金。违约金的数额不得超过用人单位提供的培训费用。\r\n\r\n第二十三条 用人单位与劳动者可以在劳动合同中约定保守用人单位的商业秘密和与知识产权相关的保密事项。对负有保密义务的劳动者，用人单位可以在劳动合同或者保密协议中与劳动者约定竞业限制条款，并约定在解除或者终止劳动合同后，在竞业限制期限内按月给予劳动者经济补偿。\r\n\r\n第二十四条 竞业限制的人员限于用人单位的高级管理人员、高级技术人员和其他负有保密义务的人员。竞业限制的范围、地域、期限由用人单位与劳动者约定，竞业限制的约定不得违反法律、法规的规定。在解除或者终止劳动合同后，前款规定的人员到与本单位生产或者经营同类产品、从事同类业务的有竞争关系的其他用人单位，或者自己开业生产或者经营同类产品、从事同类业务的竞业限制期限，不得超过二年。\r\n\r\n第三章 劳动合同的解除和终止\r\n\r\n第三十六条 用人单位与劳动者协商一致，可以解除劳动合同。\r\n\r\n第三十七条 劳动者提前三十日以书面形式通知用人单位，可以解除劳动合同。劳动者在试用期内提前三日通知用人单位，可以解除劳动合同。\r\n\r\n第三十八条 用人单位有下列情形之一的，劳动者可以解除劳动合同：（一）未按照劳动合同约定提供劳动保护或者劳动条件的；（二）未及时足额支付劳动报酬的；（三）未依法为劳动者缴纳社会保险费的；（四）用人单位的规章制度违反法律、法规的规定，损害劳动者权益的；（五）因本法第二十六条第一款规定的情形致使劳动合同无效的；（六）法律、行政法规规定劳动者可以解除劳动合同的其他情形。\r\n\r\n第四十六条 有下列情形之一的，用人单位应当向劳动者支付经济补偿：（一）劳动者依照本法第三十八条规定解除劳动合同的；（二）用人单位依照本法第三十六条规定向劳动者提出解除劳动合同并与劳动者协商一致解除劳动合同的；（三）用人单位依照本法第四十条规定解除劳动合同的；（四）用人单位依照本法第四十一条第一款规定解除劳动合同的。\r\n\r\n第四十七条 经济补偿按劳动者在本单位工作的年限，每满一年支付一个月工资的标准向劳动者支付。六个月以上不满一年的，按一年计算；不满六个月的，向劳动者支付半个月工资的经济补偿。劳动者月工资高于用人单位所在直辖市、设区的市级人民政府公布的本地区上年度职工月平均工资三倍的，向其支付经济补偿的标准按职工月平均工资三倍的数额支付，向其支付经济补偿的年限最高不超过十二年。\r\n\r\n第八十二条 用人单位自用工之日起超过一个月不满一年未与劳动者订立书面劳动合同的，应当向劳动者每月支付二倍的工资。\r\n\r\n第八十七条 用人单位违反本法规定解除或者终止劳动合同的，应当依照本法第四十七条规定的经济补偿标准的二倍向劳动者支付赔偿金。\r\n', '2026-03-08 14:18:39.180984', '.\\data\\uploads\\50fe9571-a8cc-4ef4-a726-f8c449f6739b.txt', 10201, '.txt', '50fe9571-a8cc-4ef4-a726-f8c449f6739b.txt', 28, '中华人民共和国劳动法与劳动合同法.txt', 28, 'indexed', '2026-03-08 14:22:23.067794', 'rule');
INSERT INTO `documents` VALUES (406, '中华人民共和国民法典\r\n总则编\r\n\r\n第一章 基本规定\r\n\r\n第一条 为了保护民事主体的合法权益，调整民事关系，维护社会和经济秩序，适应中国特色社会主义发展要求，弘扬社会主义核心价值观，根据宪法，制定本法。\r\n\r\n第二条 民法调整平等主体的自然人、法人和非法人组织之间的人身关系和财产关系。\r\n\r\n第三条 民事主体的人身权利、财产权利以及其他合法权益受法律保护，任何组织或者个人不得侵犯。\r\n\r\n第四条 民事主体在民事活动中的法律地位一律平等。\r\n\r\n第五条 民事主体从事民事活动，应当遵循自愿原则，按照自己的意思设立、变更、终止民事法律关系。\r\n\r\n第六条 民事主体从事民事活动，应当遵循公平原则，合理确定各方的权利和义务。\r\n\r\n第七条 民事主体从事民事活动，应当遵循诚信原则，秉持诚实，恪守承诺。\r\n\r\n第八条 民事主体从事民事活动，不得违反法律，不得违背公序良俗。\r\n\r\n第九条 民事主体从事民事活动，应当有利于节约资源、保护生态环境。\r\n\r\n第十条 处理民事纠纷，应当依照法律；法律没有规定的，可以适用习惯，但是不得违背公序良俗。\r\n\r\n第二章 自然人\r\n\r\n第一节 民事权利能力和民事行为能力\r\n\r\n第十三条 自然人从出生时起到死亡时止，具有民事权利能力，依法享有民事权利，承担民事义务。\r\n\r\n第十四条 自然人的民事权利能力一律平等。\r\n\r\n第十五条 自然人的出生时间和死亡时间，以出生证明、死亡证明记载的时间为准；没有出生证明、死亡证明的，以户籍登记或者其他有效身份登记记载的时间为准。有其他证据足以推翻以上记载时间的，以该证据证明的时间为准。\r\n\r\n第十六条 涉及遗产继承、接受赠与等胎儿利益保护的，胎儿视为具有民事权利能力。但是，胎儿娩出时为死体的，其民事权利能力自始不存在。\r\n\r\n第十七条 十八周岁以上的自然人为成年人。不满十八周岁的自然人为未成年人。\r\n\r\n第十八条 成年人为完全民事行为能力人，可以独立实施民事法律行为。十六周岁以上的未成年人，以自己的劳动收入为主要生活来源的，视为完全民事行为能力人。\r\n\r\n第十九条 八周岁以上的未成年人为限制民事行为能力人，实施民事法律行为由其法定代理人代理或者经其法定代理人同意、追认；但是，可以独立实施纯获利益的民事法律行为或者与其年龄、智力相适应的民事法律行为。\r\n\r\n第二十条 不满八周岁的未成年人为无民事行为能力人，由其法定代理人代理实施民事法律行为。\r\n\r\n第二十一条 不能辨认自己行为的成年人为无民事行为能力人，由其法定代理人代理实施民事法律行为。八周岁以上的未成年人不能辨认自己行为的，适用前款规定。\r\n\r\n第二十二条 不能完全辨认自己行为的成年人为限制民事行为能力人，实施民事法律行为由其法定代理人代理或者经其法定代理人同意、追认；但是，可以独立实施纯获利益的民事法律行为或者与其智力、精神健康状况相适应的民事法律行为。\r\n\r\n第二节 监护\r\n\r\n第二十六条 父母对未成年子女负有抚养、教育和保护的义务。成年子女对父母负有赡养、扶助和保护的义务。\r\n\r\n第二十七条 父母是未成年子女的监护人。未成年人的父母已经死亡或者没有监护能力的，由下列有监护能力的人按顺序担任监护人：（一）祖父母、外祖父母；（二）兄、姐；（三）其他愿意担任监护人的个人或者组织，但是须经未成年人住所地的居民委员会、村民委员会或者民政部门同意。\r\n\r\n第二十八条 无民事行为能力或者限制民事行为能力的成年人，由下列有监护能力的人按顺序担任监护人：（一）配偶；（二）父母、子女；（三）其他近亲属；（四）其他愿意担任监护人的个人或者组织，但是须经该成年人住所地的居民委员会、村民委员会或者民政部门同意。\r\n\r\n第三章 法人\r\n\r\n第一节 一般规定\r\n\r\n第五十七条 法人是具有民事权利能力和民事行为能力，依法独立享有民事权利和承担民事义务的组织。\r\n\r\n第五十八条 法人应当依法成立。法人应当有自己的名称、组织机构、住所、财产或者经费。法人成立的具体条件和程序，依照法律、行政法规的规定。设立法人，法律、行政法规规定须经有关机关批准的，依照其规定。\r\n\r\n第五十九条 法人的民事权利能力和民事行为能力，从法人成立时产生，到法人终止时消灭。\r\n\r\n第六十条 法人以其全部财产独立承担民事责任。\r\n\r\n第六十一条 依照法律或者法人章程的规定，代表法人从事民事活动的负责人，为法人的法定代表人。法定代表人以法人名义从事的民事活动，其法律后果由法人承受。法人章程或者法人权力机构对法定代表人代表权的限制，不得对抗善意相对人。\r\n\r\n第四章 民事法律行为\r\n\r\n第一节 一般规定\r\n\r\n第一百三十三条 民事法律行为是民事主体通过意思表示设立、变更、终止民事法律关系的行为。\r\n\r\n第一百三十四条 民事法律行为可以基于双方或者多方的意思表示一致成立，也可以基于单方的意思表示成立。法人、非法人组织依照法律或者章程规定的议事方式和表决程序作出决议的，该决议行为成立。\r\n\r\n第一百三十五条 民事法律行为可以采用书面形式、口头形式或者其他形式；法律、行政法规规定或者当事人约定采用特定形式的，应当采用特定形式。\r\n\r\n第一百四十三条 具备下列条件的民事法律行为有效：（一）行为人具有相应的民事行为能力；（二）意思表示真实；（三）不违反法律、行政法规的强制性规定，不违背公序良俗。\r\n\r\n第一百四十四条 无民事行为能力人实施的民事法律行为无效。\r\n\r\n第一百四十六条 行为人与相对人以虚假的意思表示实施的民事法律行为无效。以虚假的意思表示隐藏的民事法律行为的效力，依照有关法律规定处理。\r\n\r\n第一百四十七条 基于重大误解实施的民事法律行为，行为人有权请求人民法院或者仲裁机构予以撤销。\r\n\r\n第一百四十八条 一方以欺诈手段，使对方在违背真实意思的情况下实施的民事法律行为，受欺诈方有权请求人民法院或者仲裁机构予以撤销。\r\n\r\n第一百五十条 一方或者第三人以胁迫手段，使对方在违背真实意思的情况下实施的民事法律行为，受胁迫方有权请求人民法院或者仲裁机构予以撤销。\r\n\r\n第一百五十三条 违反法律、行政法规的强制性规定的民事法律行为无效。但是，该强制性规定不导致该民事法律行为无效的除外。违背公序良俗的民事法律行为无效。\r\n\r\n第五章 民事权利\r\n\r\n第一百零九条 自然人的人身自由、人格尊严受法律保护。\r\n\r\n第一百一十条 自然人享有生命权、身体权、健康权、姓名权、肖像权、名誉权、荣誉权、隐私权、婚姻自主权等权利。法人、非法人组织享有名称权、名誉权和荣誉权。\r\n\r\n第一百一十一条 自然人的个人信息受法律保护。任何组织或者个人需要获取他人个人信息的，应当依法取得并确保信息安全，不得非法收集、使用、加工、传输他人个人信息，不得非法买卖、提供或者公开他人个人信息。\r\n\r\n第一百一十二条 自然人因婚姻家庭关系等产生的人身权利受法律保护。\r\n\r\n第一百一十三条 民事主体的财产权利受法律平等保护。\r\n\r\n第一百一十四条 民事主体依法享有物权。物权是权利人依法对特定的物享有直接支配和排他的权利，包括所有权、用益物权和担保物权。\r\n\r\n第一百一十八条 民事主体依法享有债权。债权是因合同、侵权行为、无因管理、不当得利以及法律的其他规定，权利人请求特定义务人为或者不为一定行为的权利。\r\n\r\n第六章 民事责任\r\n\r\n第一百七十六条 民事主体依照法律规定或者按照当事人约定，履行民事义务，承担民事责任。\r\n\r\n第一百七十九条 承担民事责任的方式主要有：（一）停止侵害；（二）排除妨碍；（三）消除危险；（四）返还财产；（五）恢复原状；（六）修理、重作、更换；（七）继续履行；（八）赔偿损失；（九）支付违约金；（十）消除影响、恢复名誉；（十一）赔礼道歉。法律规定惩罚性赔偿的，依照其规定。本条规定的承担民事责任的方式，可以单独适用，也可以合并适用。\r\n\r\n第一百八十八条 向人民法院请求保护民事权利的诉讼时效期间为三年。法律另有规定的，依照其规定。诉讼时效期间自权利人知道或者应当知道权利受到损害以及义务人之日起计算。法律另有规定的，依照其规定。但是，自权利受到损害之日起超过二十年的，人民法院不予保护，有特殊情况的，人民法院可以根据权利人的申请决定延长。\r\n', '2026-03-08 14:18:43.983970', '.\\data\\uploads\\4c3d7be5-e6d2-45bb-9c4b-f3e64d5711a5.txt', 9582, '.txt', '4c3d7be5-e6d2-45bb-9c4b-f3e64d5711a5.txt', 24, '中华人民共和国民法典_总则编.txt', 24, 'indexed', '2026-03-08 14:22:25.699100', 'paragraph');
INSERT INTO `documents` VALUES (407, '中华人民共和国刑法\r\n常用条款汇编\r\n\r\n第一编 总则\r\n\r\n第一章 刑法的任务、基本原则和适用范围\r\n\r\n第一条 为了惩罚犯罪，保护人民，根据宪法，结合我国同犯罪作斗争的具体经验及实际情况，制定本法。\r\n\r\n第二条 中华人民共和国刑法的任务，是用刑罚同一切犯罪行为作斗争，以保卫国家安全，保卫人民民主专政的政权和社会主义制度，保护国有财产和劳动群众集体所有的财产，保护公民私人所有的财产，保护公民的人身权利、民主权利和其他权利，维护社会秩序、经济秩序，保障社会主义建设事业的顺利进行。\r\n\r\n第三条 法律明文规定为犯罪行为的，依照法律定罪处刑；法律没有明文规定为犯罪行为的，不得定罪处刑。\r\n\r\n第四条 对任何人犯罪，在适用法律上一律平等。不允许任何人有超越法律的特权。\r\n\r\n第五条 刑罚的轻重，应当与犯罪分子所犯罪行和承担的刑事责任相适应。\r\n\r\n第二章 犯罪\r\n\r\n第一节 犯罪和刑事责任\r\n\r\n第十三条 一切危害国家主权、领土完整和安全，分裂国家、颠覆人民民主专政的政权和推翻社会主义制度，破坏社会秩序和经济秩序，侵犯国有财产或者劳动群众集体所有的财产，侵犯公民私人所有的财产，侵犯公民的人身权利、民主权利和其他权利，以及其他危害社会的行为，依照法律应当受刑罚处罚的，都是犯罪，但是情节显著轻微危害不大的，不认为是犯罪。\r\n\r\n第十四条 明知自己的行为会发生危害社会的结果，并且希望或者放任这种结果发生，因而构成犯罪的，是故意犯罪。故意犯罪，应当负刑事责任。\r\n\r\n第十五条 应当预见自己的行为可能发生危害社会的结果，因为疏忽大意而没有预见，或者已经预见而轻信能够避免，以致发生这种结果的，是过失犯罪。过失犯罪，法律有规定的才负刑事责任。\r\n\r\n第十七条 已满十六周岁的人犯罪，应当负刑事责任。已满十四周岁不满十六周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。已满十二周岁不满十四周岁的人，犯故意杀人、故意伤害罪，致人死亡或者以特别残忍手段致人重伤造成严重残疾，情节恶劣，经最高人民检察院核准追诉的，应当负刑事责任。\r\n\r\n第二十条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在进行的不法侵害，而采取的制止不法侵害的行为，对不法侵害人造成损害的，属于正当防卫，不负刑事责任。正当防卫明显超过必要限度造成重大损害的，应当负刑事责任，但是应当减轻或者免除处罚。对正在进行行凶、杀人、抢劫、强奸、绑架以及其他严重危及人身安全的暴力犯罪，采取防卫行为，造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。\r\n\r\n第二十一条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在发生的危险，不得已采取的紧急避险行为，造成损害的，不负刑事责任。紧急避险超过必要限度造成不应有的损害的，应当负刑事责任，但是应当减轻或者免除处罚。\r\n\r\n第三章 刑罚\r\n\r\n第三十三条 主刑的种类如下：（一）管制；（二）拘役；（三）有期徒刑；（四）无期徒刑；（五）死刑。\r\n\r\n第三十四条 附加刑的种类如下：（一）罚金；（二）剥夺政治权利；（三）没收财产。附加刑也可以独立适用。\r\n\r\n第三十八条 管制的期限，为三个月以上二年以下。\r\n\r\n第四十二条 拘役的期限，为一个月以上六个月以下。\r\n\r\n第四十五条 有期徒刑的期限，为六个月以上十五年以下。\r\n\r\n第四十八条 死刑只适用于罪行极其严重的犯罪分子。对于应当判处死刑的犯罪分子，如果不是必须立即执行的，可以判处死刑同时宣告缓期二年执行。\r\n\r\n第六十七条 犯罪以后自动投案，如实供述自己的罪行的，是自首。对于自首的犯罪分子，可以从轻或者减轻处罚。其中，犯罪较轻的，可以免除处罚。\r\n\r\n第六十八条 犯罪分子有揭发他人犯罪行为，查证属实的，或者提供重要线索，从而得以侦破其他案件等立功表现的，可以从轻或者减轻处罚；有重大立功表现的，可以减轻或者免除处罚。\r\n\r\n第七十二条 对于被判处拘役、三年以下有期徒刑的犯罪分子，同时符合下列条件的，可以宣告缓刑，对其中不满十八周岁的人、怀孕的妇女和已满七十五周岁的人，应当宣告缓刑：（一）犯罪情节较轻；（二）有悔罪表现；（三）没有再犯罪的危险；（四）宣告缓刑对所居住社区没有重大不良影响。\r\n\r\n第二编 分则\r\n\r\n第四章 侵犯公民人身权利、民主权利罪\r\n\r\n第二百三十二条 故意杀人的，处死刑、无期徒刑或者十年以上有期徒刑；情节较轻的，处三年以上十年以下有期徒刑。\r\n\r\n第二百三十三条 过失致人死亡的，处三年以上七年以下有期徒刑；情节较轻的，处三年以下有期徒刑。\r\n\r\n第二百三十四条 故意伤害他人身体的，处三年以下有期徒刑、拘役或者管制。犯前款罪，致人重伤的，处三年以上十年以下有期徒刑；致人死亡或者以特别残忍手段致人重伤造成严重残疾的，处十年以上有期徒刑、无期徒刑或者死刑。\r\n\r\n第二百三十六条 以暴力、胁迫或者其他手段强奸妇女的，处三年以上十年以下有期徒刑。\r\n\r\n第二百三十八条 非法拘禁他人或者以其他方法非法剥夺他人人身自由的，处三年以下有期徒刑、拘役、管制或者剥夺政治权利。具有殴打、侮辱情节的，从重处罚。\r\n\r\n第二百四十条 拐卖妇女、儿童的，处五年以上十年以下有期徒刑，并处罚金；情节严重的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产；情节特别严重的，处死刑，并处没收财产。\r\n\r\n第二百四十六条 以暴力或者其他方法公然侮辱他人或者捏造事实诽谤他人，情节严重的，处三年以下有期徒刑、拘役、管制或者剥夺政治权利。\r\n\r\n第二百五十三条之一 违反国家有关规定，向他人出售或者提供公民个人信息，情节严重的，处三年以下有期徒刑或者拘役，并处或者单处罚金；情节特别严重的，处三年以上七年以下有期徒刑，并处罚金。\r\n\r\n第五章 侵犯财产罪\r\n\r\n第二百六十三条 以暴力、胁迫或者其他方法抢劫公私财物的，处三年以上十年以下有期徒刑，并处罚金；有下列情形之一的，处十年以上有期徒刑、无期徒刑或者死刑，并处罚金或者没收财产：（一）入户抢劫的；（二）在公共交通工具上抢劫的；（三）抢劫银行或者其他金融机构的；（四）多次抢劫或者抢劫数额巨大的；（五）抢劫致人重伤、死亡的；（六）冒充军警人员抢劫的；（七）持枪抢劫的；（八）抢劫军用物资或者抢险、救灾、救济物资的。\r\n\r\n第二百六十四条 盗窃公私财物，数额较大的，或者多次盗窃、入户盗窃、携带凶器盗窃、扒窃的，处三年以下有期徒刑、拘役或者管制，并处或者单处罚金；数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金；数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产。\r\n\r\n第二百六十六条 诈骗公私财物，数额较大的，处三年以下有期徒刑、拘役或者管制，并处或者单处罚金；数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金；数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产。\r\n\r\n第二百七十条 将代为保管的他人财物非法占为己有，数额较大，拒不退还的，处二年以下有期徒刑、拘役或者罚金；数额巨大或者有其他严重情节的，处二年以上五年以下有期徒刑，并处罚金。将他人的遗忘物或者埋藏物非法占为己有，数额较大，拒不交出的，依照前款的规定处罚。\r\n\r\n第二百七十四条 敲诈勒索公私财物，数额较大或者多次敲诈勒索的，处三年以下有期徒刑、拘役或者管制，并处或者单处罚金；数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金；数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑，并处罚金。\r\n\r\n第六章 妨害社会管理秩序罪\r\n\r\n第二百九十一条之一 编造虚假的险情、疫情、灾情、警情，在信息网络或者其他媒体上传播，或者明知是上述虚假信息，故意在信息网络或者其他媒体上传播，严重扰乱社会秩序的，处三年以下有期徒刑、拘役或者管制；造成严重后果的，处三年以上七年以下有期徒刑。\r\n\r\n第二百九十三条 有下列寻衅滋事行为之一，破坏社会秩序的，处五年以下有期徒刑、拘役或者管制：（一）随意殴打他人，情节恶劣的；（二）追逐、拦截、辱骂、恐吓他人，情节恶劣的；（三）强拿硬要或者任意损毁、占用公私财物，情节严重的；（四）在公共场所起哄闹事，造成公共场所秩序严重混乱的。\r\n\r\n第八章 贪污贿赂罪\r\n\r\n第三百八十二条 国家工作人员利用职务上的便利，侵吞、窃取、骗取或者以其他手段非法占有公共财物的，是贪污罪。\r\n\r\n第三百八十三条 对犯贪污罪的，根据情节轻重，分别依照下列规定处罚：贪污数额较大或者有其他较重情节的，处三年以下有期徒刑或者拘役，并处罚金。贪污数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金或者没收财产。贪污数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产；数额特别巨大，并使国家和人民利益遭受特别重大损失的，处无期徒刑或者死刑，并处没收财产。\r\n\r\n第三百八十五条 国家工作人员利用职务上的便利，索取他人财物的，或者非法收受他人财物，为他人谋取利益的，是受贿罪。\r\n\r\n第三百八十九条 为谋取不正当利益，给予国家工作人员以财物的，是行贿罪。\r\n\r\n第三百九十七条 国家机关工作人员滥用职权或者玩忽职守，致使公共财产、国家和人民利益遭受重大损失的，处三年以下有期徒刑或者拘役；情节特别严重的，处三年以上七年以下有期徒刑。\r\n', '2026-03-08 14:18:46.361244', '.\\data\\uploads\\e18cb690-8586-45c7-a0a6-fd4004c3a761.txt', 11237, '.txt', 'e18cb690-8586-45c7-a0a6-fd4004c3a761.txt', 29, '中华人民共和国刑法_常用条款.txt', 29, 'indexed', '2026-03-08 14:22:22.395291', 'semantic');
INSERT INTO `documents` VALUES (408, '中华人民共和国知识产权法律与网络安全法\r\n重要条款汇编\r\n\r\n第一部分 著作权法\r\n\r\n第一章 总则\r\n\r\n第一条 为保护文学、艺术和科学作品作者的著作权，以及与著作权有关的权益，鼓励有益于社会主义精神文明、物质文明建设的作品的创作和传播，促进社会主义文化和科学事业的发展与繁荣，根据宪法制定本法。\r\n\r\n第三条 本法所称的作品，是指文学、艺术和科学领域内具有独创性并能以一定形式表现的智力成果，包括：（一）文字作品；（二）口述作品；（三）音乐、戏剧、曲艺、舞蹈、杂技艺术作品；（四）美术、建筑作品；（五）摄影作品；（六）视听作品；（七）工程设计图、产品设计图、地图、示意图等图形作品和模型作品；（八）计算机软件；（九）符合作品特征的其他智力成果。\r\n\r\n第十条 著作权包括下列人身权和财产权：（一）发表权；（二）署名权；（三）修改权；（四）保护作品完整权；（五）复制权；（六）发行权；（七）出租权；（八）展览权；（九）表演权；（十）放映权；（十一）广播权；（十二）信息网络传播权；（十三）摄制权；（十四）改编权；（十五）翻译权；（十六）汇编权；（十七）应当由著作权人享有的其他权利。\r\n\r\n第二十二条 作品的著作权属于作者。由法人或者非法人组织主持，代表法人或者非法人组织意志创作，并由法人或者非法人组织承担责任的作品，法人或者非法人组织视为作者。\r\n\r\n第二十四条 在下列情况下使用作品，可以不经著作权人许可，不向其支付报酬，但应当指明作者姓名或者名称、作品名称，并且不得影响该作品的正常使用，也不得不合理地损害著作权人的合法权益：（一）为个人学习、研究或者欣赏，使用他人已经发表的作品；（二）为介绍、评论某一作品或者说明某一问题，在作品中适当引用他人已经发表的作品；（三）为报道新闻，在报纸、期刊、广播电台、电视台等媒体中不可避免地再现或者引用已经发表的作品。\r\n\r\n第五十二条 有下列侵权行为的，应当根据情况，承担停止侵害、消除影响、赔礼道歉、赔偿损失等民事责任：（一）未经著作权人许可，发表其作品的；（二）未经合作作者许可，将与他人合作创作的作品当作自己单独创作的作品发表的；（三）没有参加创作，为谋取个人名利，在他人作品上署名的；（四）歪曲、篡改他人作品的；（五）剽窃他人作品的。\r\n\r\n第二部分 专利法\r\n\r\n第一条 为了保护专利权人的合法权益，鼓励发明创造，推动发明创造的应用，提高创新能力，促进科学技术进步和经济社会发展，制定本法。\r\n\r\n第二条 本法所称的发明创造是指发明、实用新型和外观设计。发明，是指对产品、方法或者其改进所提出的新的技术方案。实用新型，是指对产品的形状、构造或者其结合所提出的适于实用的新的技术方案。外观设计，是指对产品的整体或者局部的形状、图案或者其结合以及色彩与形状、图案的结合所作出的富有美感并适于工业应用的新设计。\r\n\r\n第四十二条 发明专利权的期限为二十年，实用新型专利权的期限为十年，外观设计专利权的期限为十五年，均自申请日起计算。\r\n\r\n第六十五条 未经专利权人许可，实施其专利，即侵犯其专利权，引起纠纷的，由当事人协商解决；不愿协商或者协商不成的，专利权人或者利害关系人可以向人民法院起诉，也可以请求管理专利工作的部门处理。\r\n\r\n第三部分 商标法\r\n\r\n第一条 为了加强商标管理，保护商标专用权，促使生产、经营者保证商品和服务质量，维护商标信誉，以保障消费者和生产、经营者的利益，促进社会主义市场经济的发展，特制定本法。\r\n\r\n第三条 经商标局核准注册的商标为注册商标，包括商品商标、服务商标和集体商标、证明商标；商标注册人享有商标专用权，受法律保护。\r\n\r\n第三十九条 注册商标的有效期为十年，自核准注册之日起计算。\r\n\r\n第五十七条 有下列行为之一的，均属侵犯注册商标专用权：（一）未经商标注册人的许可，在同一种商品上使用与其注册商标相同的商标的；（二）未经商标注册人的许可，在同一种商品上使用与其注册商标近似的商标，或者在类似商品上使用与其注册商标相同或者近似的商标，容易导致混淆的；（三）销售侵犯注册商标专用权的商品的；（四）伪造、擅自制造他人注册商标标识或者销售伪造、擅自制造的注册商标标识的。\r\n\r\n第四部分 网络安全法\r\n\r\n第一条 为了保障网络安全，维护网络空间主权和国家安全、社会公共利益，保护公民、法人和其他组织的合法权益，促进经济社会信息化健康发展，制定本法。\r\n\r\n第九条 网络运营者开展经营和服务活动，必须遵守法律、行政法规，尊重社会公德，遵守商业道德，诚实信用，履行网络安全保护义务，接受政府和社会的监督，承担社会责任。\r\n\r\n第二十一条 国家实行网络安全等级保护制度。网络运营者应当按照网络安全等级保护制度的要求，履行下列安全保护义务：（一）制定内部安全管理制度和操作规程，确定网络安全负责人，落实网络安全保护责任；（二）采取防范计算机病毒和网络攻击、网络侵入等危害网络安全行为的技术措施；（三）采取监测、记录网络运行状态、网络安全事件的技术措施，并按照规定留存相关的网络日志不少于六个月；（四）采取数据分类、重要数据备份和加密等措施。\r\n\r\n第四十条 网络运营者应当对其收集的用户信息严格保密，并建立健全用户信息保护制度。\r\n\r\n第四十一条 网络运营者收集、使用个人信息，应当遵循合法、正当、必要的原则，公开收集、使用规则，明示收集、使用信息的目的、方式和范围，并经被收集者同意。网络运营者不得收集与其提供的服务无关的个人信息，不得违反法律、行政法规的规定和双方的约定收集、使用个人信息，并应当依照法律、行政法规的规定和与用户的约定，处理其保存的个人信息。\r\n\r\n第四十二条 网络运营者不得泄露、篡改、毁损其收集的个人信息；未经被收集者同意，不得向他人提供个人信息。但是，经过处理无法识别特定个人且不能复原的除外。\r\n\r\n第四十四条 任何个人和组织不得窃取或者以其他非法方式获取个人信息，不得非法出售或者非法向他人提供个人信息。\r\n\r\n第六十四条 网络运营者、网络产品或者服务的提供者违反本法第二十二条第三款、第四十一条至第四十三条规定，侵害个人信息依法得到保护的权利的，由有关主管部门责令改正，可以根据情节单处或者并处警告、没收违法所得、处违法所得一倍以上十倍以下罚款，没有违法所得的，处一百万元以下罚款，对直接负责的主管人员和其他直接责任人员处一万元以上十万元以下罚款；情节严重的，并可以责令暂停相关业务、停业整顿、关闭网站、吊销相关业务许可证或者吊销营业执照。\r\n', '2026-03-08 14:18:49.104958', '.\\data\\uploads\\dc89b693-4382-48eb-ae99-e8736bc08a2b.txt', 7765, '.txt', 'dc89b693-4382-48eb-ae99-e8736bc08a2b.txt', 20, '中华人民共和国知识产权与网络安全法.txt', 20, 'indexed', '2026-03-08 14:22:22.288341', 'rule');
INSERT INTO `documents_seq` VALUES (501);
INSERT INTO `messages` VALUES (702, '刑法基本原则是什么？', 852, '2026-03-08 14:24:03.905273', 'user', NULL);
INSERT INTO `messages` VALUES (703, '根据您提供的法律条文片段，我无法直接回答“刑法基本原则是什么”这个问题。\n\n**原因如下：**\n您提供的条文片段主要涉及《中华人民共和国刑法》的任务（第二条）以及其他法律的立法目的和原则，但并未包含关于刑法基本原则的具体规定。刑法的基本原则（如罪刑法定原则、适用刑法人人平等原则、罪责刑相适应原则等）通常规定在《刑法》第三条至第五条。\n\n**相关条文引用：**\n- 您提供的【来源1】和【来源2】是《中华人民共和国刑法》第二条，它阐述了刑法的任务，而非基本原则。\n- 其他来源（【来源3】、【来源4】、【来源5】）分别属于《交通安全与治安管理法》和《行政处罚法》，与刑法基本原则无关。\n\n**建议：**\n由于提供的法律条文片段信息不足，我无法基于现有材料给出准确回答。建议您查阅《中华人民共和国刑法》总则部分第三条至第五条的完整内容，或就具体的法律原则问题咨询专业律师。', 852, '2026-03-08 14:24:03.906277', 'assistant', '[{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第一章 刑法的任务、基本原则和适用范围\",\"distance\":0.7592997550964355,\"content\":\"第二条 中华人民共和国刑法的任务，是用刑罚同一切犯罪行为作斗争，以保卫国家安全，保卫人民民主专政的政权和社会主义制度，保护国有财产和劳动群众集体所有的财产，保护公民私人所有的财产，保护公民的人身权利、民主权利和其他权利，维护社会秩序、经济秩序，保障社会主义建设事业的顺利进行。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第一章 刑法的任务、基本原则和适用范围\",\"distance\":0.7592998743057251,\"content\":\"第二条 中华人民共和国刑法的任务，是用刑罚同一切犯罪行为作斗争，以保卫国家安全，保卫人民民主专政的政权和社会主义制度，保护国有财产和劳动群众集体所有的财产，保护公民私人所有的财产，保护公民的人身权利、民主权利和其他权利，维护社会秩序、经济秩序，保障社会主义建设事业的顺利进行。\"},{\"document_name\":\"中华人民共和国交通安全与治安管理法.txt\",\"chapter_info\":\"第一章 总则\",\"distance\":0.8155617682627472,\"content\":\"第一条 为维护社会治安秩序，保障公共安全，保护公民、法人和其他组织的合法权益，规范和保障公安机关及其人民警察依法履行治安管理职责，制定本法。\"},{\"document_name\":\"中华人民共和国交通安全与治安管理法.txt\",\"chapter_info\":\"\",\"distance\":0.815561830997467,\"content\":\"第一条 为维护社会治安秩序，保障公共安全，保护公民、法人和其他组织的合法权益，规范和保障公安机关及其人民警察依法履行治安管理职责，制定本法。\"},{\"document_name\":\"行政处罚法..pdf\",\"chapter_info\":\"第一章 总则\",\"distance\":0.8436703240210321,\"content\":\"第五条 设定和实施行政处罚必须以事实为依据，与违法行为的事实、性质、情节以及社会危害程度相\\n当。\\n实施行政处罚，纠正违法行为，应当坚持处罚与教育相结合，教育公民、法人或者其他组织自觉守法。\"}]');
INSERT INTO `messages` VALUES (704, '16岁的男孩抢走路人贵重物品应该负刑事责任吗？', 852, '2026-03-08 14:25:24.115608', 'user', NULL);
INSERT INTO `messages` VALUES (705, '根据您提供的法律条文片段，**16岁的男孩抢走路人贵重物品，应当负刑事责任。**\n\n**法律依据与解释：**\n\n1.  **刑事责任年龄规定**：根据《中华人民共和国刑法》第十七条（来源1、来源2），**已满十六周岁的人犯罪，应当负刑事责任**。本案中，行为人年龄为16岁，已完全达到法定的刑事责任年龄，需要对自己实施的犯罪行为承担刑事责任。\n\n2.  **行为定性**：“抢走路人贵重物品”这一行为，如果符合以暴力、胁迫或者其他方法强行夺取公私财物的特征，通常构成**抢劫罪**。抢劫罪属于严重的暴力犯罪。\n\n3.  **具体适用**：虽然条文也规定了已满十四周岁不满十六周岁的人，仅对八种特定严重犯罪（包括抢劫）负刑事责任，但本案行为人已满十六周岁，直接适用“应当负刑事责任”的一般规定，无需再考虑其是否属于那八种特定犯罪。\n\n**结论：**\n因此，一名16岁的男孩实施抢劫行为，根据《中华人民共和国刑法》第十七条的规定，**应当承担相应的刑事责任**。\n\n**建议：**\n具体的定罪量刑（如构成抢劫罪还是抢夺罪，以及判处何种刑罚）需要结合案件的具体情节（如是否使用暴力、暴力程度、财物价值等）来判定。对于涉及未成年人犯罪的具体案件处理，建议咨询专业律师或由司法机关依法审理。', 852, '2026-03-08 14:25:24.120633', 'assistant', '[{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第一节 犯罪和刑事责任\",\"distance\":0.585975170135498,\"content\":\"第十七条 已满十六周岁的人犯罪，应当负刑事责任。已满十四周岁不满十六周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。已满十二周岁不满十四周岁的人，犯故意杀人、故意伤害罪，致人死亡或者以特别残忍手段致人重伤造成严重残疾，情节恶劣，经最高人民检察院核准追诉的，应当负刑事责任。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第二章 犯罪 第一节 犯罪和刑事责任\",\"distance\":0.5859754085540771,\"content\":\"第十七条 已满十六周岁的人犯罪，应当负刑事责任。已满十四周岁不满十六周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。已满十二周岁不满十四周岁的人，犯故意杀人、故意伤害罪，致人死亡或者以特别残忍手段致人重伤造成严重残疾，情节恶劣，经最高人民检察院核准追诉的，应当负刑事责任。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第一节 犯罪和刑事责任\",\"distance\":0.7457646131515503,\"content\":\"第二十条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在进行的不法侵害，而采取的制止不法侵害的行为，对不法侵害人造成损害的，属于正当防卫，不负刑事责任。正当防卫明显超过必要限度造成重大损害的，应当负刑事责任，但是应当减轻或者免除处罚。对正在进行行凶、杀人、抢劫、强奸、绑架以及其他严重危及人身安全的暴力犯罪，采取防卫行为，造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第二章 犯罪 第一节 犯罪和刑事责任\",\"distance\":0.7457647323608398,\"content\":\"第二十条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在进行的不法侵害，而采取的制止不法侵害的行为，对不法侵害人造成损害的，属于正当防卫，不负刑事责任。正当防卫明显超过必要限度造成重大损害的，应当负刑事责任，但是应当减轻或者免除处罚。对正在进行行凶、杀人、抢劫、强奸、绑架以及其他严重危及人身安全的暴力犯罪，采取防卫行为，造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第三章 刑罚 第一节 犯罪和刑事责任\",\"distance\":0.7711124420166016,\"content\":\"第二十一条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在发生的危险，不得已采取的紧急避险行为，造成损害的，不负刑事责任。紧急避险超过必要限度造成不应有的损害的，应当负刑事责任，但是应当减轻或者免除处罚。\"}]');
INSERT INTO `messages` VALUES (706, '14岁的男孩呢？', 852, '2026-03-08 14:26:01.340073', 'user', NULL);
INSERT INTO `messages` VALUES (707, '根据您提供的法律条文片段，对于“14岁的男孩”实施违法行为或犯罪行为，其法律责任需要根据**行为的性质（是治安违法行为还是犯罪行为）** 来具体判断。\n\n**法律依据与解释：**\n\n1.  **如果14岁男孩的行为属于违反治安管理的违法行为（例如：打架斗殴、偷窃少量财物等未构成犯罪的行为）**：\n    *   **法律依据**：《中华人民共和国交通安全与治安管理法》第十二条（来源2、来源3）。\n    *   **规定内容**：已满十四周岁不满十八周岁的人违反治安管理的，**从轻或者减轻处罚**。\n    *   **结论**：在这种情况下，14岁的男孩需要承担治安管理处罚责任，但依法应当从轻或减轻处罚。\n\n2.  **如果14岁男孩的行为构成了特定的严重犯罪**：\n    *   **法律依据**：《中华人民共和国刑法》第十七条（来源4、来源5）。\n    *   **规定内容**：已满十四周岁不满十六周岁的人，犯**故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪**的，应当负刑事责任。\n    *   **结论**：如果14岁男孩实施了上述八种严重犯罪行为之一（例如：抢劫、故意杀人等），则**应当承担刑事责任**。对于这八种罪名之外的其他犯罪行为，则不负刑事责任。\n\n3.  **如果14岁男孩的行为属于一般违法行为但不构成犯罪**：\n    *   **法律依据**：《行政处罚法》第三十条（来源1）。\n    *   **规定内容**：已满十四周岁不满十八周岁的人有违法行为的，**应当从轻或者减轻行政处罚**。\n    *   **结论**：在这种情况下，他需要承担行政处罚责任，但同样应当从轻或减轻处罚。\n\n**总结回答：**\n对于14岁的男孩：\n*   **若其行为构成《刑法》第十七条所列的八种严重犯罪（如抢劫、故意杀人等）**，则**应当负刑事责任**（依据《中华人民共和国刑法》第十七条）。\n*   **若其行为属于违反治安管理或其他行政违法行为**，则**需要承担相应的法律责任（处罚）**，但依法**应当从轻或者减轻处罚**（依据《中华人民共和国交通安全与治安管理法》第十二条或《行政处罚法》第三十条）。\n\n**核心提示：**\n**行为的定性（是犯罪还是违法）是判断其责任的关键。** 由于您未提供14岁男孩具体实施了何种行为，以上是根据不同情形进行的法律分析。对于具体案件，建议咨询专业法律人士。', 852, '2026-03-08 14:26:01.345078', 'assistant', '[{\"document_name\":\"行政处罚法..pdf\",\"chapter_info\":\"第三章 行政处罚的管辖和适用\",\"distance\":0.9288134850483681,\"content\":\"第三十条 不满十四周岁的人有违法行为的，不予行政处罚，责令监护人加以管教；已满十四周岁不满十\\n八周岁的人有违法行为的，应当从轻或者减轻行政处罚。\"},{\"document_name\":\"中华人民共和国交通安全与治安管理法.txt\",\"chapter_info\":\"第二章 处罚的种类和适用\",\"distance\":1.0145079365262826,\"content\":\"第十二条 已满十四周岁不满十八周岁的人违反治安管理的，从轻或者减轻处罚；不满十四周岁的人违反治安管理的，不予处罚，但是应当责令其监护人严加管教。\"},{\"document_name\":\"中华人民共和国交通安全与治安管理法.txt\",\"chapter_info\":\"\",\"distance\":1.0145081281661987,\"content\":\"第十二条 已满十四周岁不满十八周岁的人违反治安管理的，从轻或者减轻处罚；不满十四周岁的人违反治安管理的，不予处罚，但是应当责令其监护人严加管教。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第一节 犯罪和刑事责任\",\"distance\":1.0853749513626099,\"content\":\"第十七条 已满十六周岁的人犯罪，应当负刑事责任。已满十四周岁不满十六周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。已满十二周岁不满十四周岁的人，犯故意杀人、故意伤害罪，致人死亡或者以特别残忍手段致人重伤造成严重残疾，情节恶劣，经最高人民检察院核准追诉的，应当负刑事责任。\"},{\"document_name\":\"中华人民共和国刑法_常用条款.txt\",\"chapter_info\":\"第二章 犯罪 第一节 犯罪和刑事责任\",\"distance\":1.0853753089904785,\"content\":\"第十七条 已满十六周岁的人犯罪，应当负刑事责任。已满十四周岁不满十六周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。已满十二周岁不满十四周岁的人，犯故意杀人、故意伤害罪，致人死亡或者以特别残忍手段致人重伤造成严重残疾，情节恶劣，经最高人民检察院核准追诉的，应当负刑事责任。\"}]');
INSERT INTO `messages_seq` VALUES (801);
INSERT INTO `segments` VALUES (1502, '第一章 总则', '第一条 为保护文学、艺术和科学作品作者的著作权，以及与著作权有关的权益，鼓励有益于社会主义精神文明、物质文明建设的作品的创作和传播，促进社会主义文化和科学事业的发展与繁荣，根据宪法制定本法。', '2026-03-08 14:18:53.725856', 408, 95, b'1', 0, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 0, 'doc_408_seg_0', 'rule');
INSERT INTO `segments` VALUES (1503, '第一章 总则', '第三条 本法所称的作品，是指文学、艺术和科学领域内具有独创性并能以一定形式表现的智力成果，包括：（一）文字作品；（二）口述作品；（三）音乐、戏剧、曲艺、舞蹈、杂技艺术作品；（四）美术、建筑作品；（五）摄影作品；（六）视听作品；（七）工程设计图、产品设计图、地图、示意图等图形作品和模型作品；（八）计算机软件；（九）符合作品特征的其他智力成果。', '2026-03-08 14:18:53.727856', 408, 266, b'1', 1, '{\"keywords\":[\"第三条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第三条\",\"type\":\"ARTICLE_REF\"}]}', 95, 'doc_408_seg_1', 'rule');
INSERT INTO `segments` VALUES (1504, '第一章 总则', '第十条 著作权包括下列人身权和财产权：（一）发表权；（二）署名权；（三）修改权；（四）保护作品完整权；（五）复制权；（六）发行权；（七）出租权；（八）展览权；（九）表演权；（十）放映权；（十一）广播权；（十二）信息网络传播权；（十三）摄制权；（十四）改编权；（十五）翻译权；（十六）汇编权；（十七）应当由著作权人享有的其他权利。', '2026-03-08 14:18:53.728856', 408, 430, b'1', 2, '{\"keywords\":[\"第十条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"GPE\"],\"legal_entities\":[{\"text\":\"第十条\",\"type\":\"ARTICLE_REF\"}]}', 266, 'doc_408_seg_2', 'rule');
INSERT INTO `segments` VALUES (1505, '第一章 总则', '第二十二条 作品的著作权属于作者。由法人或者非法人组织主持，代表法人或者非法人组织意志创作，并由法人或者非法人组织承担责任的作品，法人或者非法人组织视为作者。', '2026-03-08 14:18:53.729856', 408, 509, b'1', 3, '{\"keywords\":[\"第二十二条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\"],\"legal_entities\":[{\"text\":\"第二十二条\",\"type\":\"ARTICLE_REF\"}]}', 430, 'doc_408_seg_3', 'rule');
INSERT INTO `segments` VALUES (1506, '第一章 总则', '第二十四条 在下列情况下使用作品，可以不经著作权人许可，不向其支付报酬，但应当指明作者姓名或者名称、作品名称，并且不得影响该作品的正常使用，也不得不合理地损害著作权人的合法权益：（一）为个人学习、研究或者欣赏，使用他人已经发表的作品；（二）为介绍、评论某一作品或者说明某一问题，在作品中适当引用他人已经发表的作品；（三）为报道新闻，在报纸、期刊、广播电台、电视台等媒体中不可避免地再现或者引用已经发表的作品。', '2026-03-08 14:18:53.730858', 408, 713, b'1', 4, '{\"keywords\":[\"第二十四条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十四条\",\"type\":\"ARTICLE_REF\"}]}', 509, 'doc_408_seg_4', 'rule');
INSERT INTO `segments` VALUES (1507, '第一章 总则', '第五十二条 有下列侵权行为的，应当根据情况，承担停止侵害、消除影响、赔礼道歉、赔偿损失等民事责任：（一）未经著作权人许可，发表其作品的；（二）未经合作作者许可，将与他人合作创作的作品当作自己单独创作的作品发表的；（三）没有参加创作，为谋取个人名利，在他人作品上署名的；（四）歪曲、篡改他人作品的；（五）剽窃他人作品的。\n第二部分 专利法', '2026-03-08 14:18:53.730858', 408, 881, b'1', 5, '{\"keywords\":[\"第五十二条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第五十二条\",\"type\":\"ARTICLE_REF\"}]}', 713, 'doc_408_seg_5', 'rule');
INSERT INTO `segments` VALUES (1508, '第一章 总则', '第一条 为了保护专利权人的合法权益，鼓励发明创造，推动发明创造的应用，提高创新能力，促进科学技术进步和经济社会发展，制定本法。', '2026-03-08 14:18:53.731856', 408, 944, b'1', 6, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 881, 'doc_408_seg_6', 'rule');
INSERT INTO `segments` VALUES (1509, '第一章 总则', '第二条 本法所称的发明创造是指发明、实用新型和外观设计。发明，是指对产品、方法或者其改进所提出的新的技术方案。实用新型，是指对产品的形状、构造或者其结合所提出的适于实用的新的技术方案。外观设计，是指对产品的整体或者局部的形状、图案或者其结合以及色彩与形状、图案的结合所作出的富有美感并适于工业应用的新设计。', '2026-03-08 14:18:53.732857', 408, 1097, b'1', 7, '{\"keywords\":[\"第二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 944, 'doc_408_seg_7', 'rule');
INSERT INTO `segments` VALUES (1510, '第一章 总则', '第四十二条 发明专利权的期限为二十年，实用新型专利权的期限为十年，外观设计专利权的期限为十五年，均自申请日起计算。', '2026-03-08 14:18:53.733860', 408, 1154, b'1', 8, '{\"keywords\":[\"第四十二条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第四十二条\",\"type\":\"ARTICLE_REF\"}]}', 1097, 'doc_408_seg_8', 'rule');
INSERT INTO `segments` VALUES (1511, '第一章 总则', '第六十五条 未经专利权人许可，实施其专利，即侵犯其专利权，引起纠纷的，由当事人协商解决；不愿协商或者协商不成的，专利权人或者利害关系人可以向人民法院起诉，也可以请求管理专利工作的部门处理。\n第三部分 商标法', '2026-03-08 14:18:53.734856', 408, 1257, b'1', 9, '{\"keywords\":[\"第六十五条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第六十五条\",\"type\":\"ARTICLE_REF\"}]}', 1154, 'doc_408_seg_9', 'rule');
INSERT INTO `segments` VALUES (1512, '第一章 总则', '第一条 为了加强商标管理，保护商标专用权，促使生产、经营者保证商品和服务质量，维护商标信誉，以保障消费者和生产、经营者的利益，促进社会主义市场经济的发展，特制定本法。', '2026-03-08 14:18:53.735859', 408, 1340, b'1', 10, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 1257, 'doc_408_seg_10', 'rule');
INSERT INTO `segments` VALUES (1513, '第一章 总则', '第三条 经商标局核准注册的商标为注册商标，包括商品商标、服务商标和集体商标、证明商标；商标注册人享有商标专用权，受法律保护。', '2026-03-08 14:18:53.735859', 408, 1402, b'1', 11, '{\"keywords\":[\"第三条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第三条\",\"type\":\"ARTICLE_REF\"}]}', 1340, 'doc_408_seg_11', 'rule');
INSERT INTO `segments` VALUES (1514, '第一章 总则', '第五十七条 有下列行为之一的，均属侵犯注册商标专用权：（一）未经商标注册人的许可，在同一种商品上使用与其注册商标相同的商标的；（二）未经商标注册人的许可，在同一种商品上使用与其注册商标近似的商标，或者在类似商品上使用与其注册商标相同或者近似的商标，容易导致混淆的；（三）销售侵犯注册商标专用权的商品的；（四）伪造、擅自制造他人注册商标标识或者销售伪造、擅自制造的注册商标标识的。\n第四部分 网络安全法', '2026-03-08 14:18:53.736855', 408, 1602, b'1', 12, '{\"keywords\":[\"第五十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第五十七条\",\"type\":\"ARTICLE_REF\"}]}', 1402, 'doc_408_seg_12', 'rule');
INSERT INTO `segments` VALUES (1515, '第一章 总则', '第一条 为了保障网络安全，维护网络空间主权和国家安全、社会公共利益，保护公民、法人和其他组织的合法权益，促进经济社会信息化健康发展，制定本法。', '2026-03-08 14:18:53.736855', 408, 1673, b'1', 13, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 1602, 'doc_408_seg_13', 'rule');
INSERT INTO `segments` VALUES (1516, '第一章 总则', '第九条 网络运营者开展经营和服务活动，必须遵守法律、行政法规，尊重社会公德，遵守商业道德，诚实信用，履行网络安全保护义务，接受政府和社会的监督，承担社会责任。', '2026-03-08 14:18:53.738082', 408, 1752, b'1', 14, '{\"keywords\":[\"第九条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第九条\",\"type\":\"ARTICLE_REF\"}]}', 1673, 'doc_408_seg_14', 'rule');
INSERT INTO `segments` VALUES (1517, '第一章 总则', '第二十一条 国家实行网络安全等级保护制度。网络运营者应当按照网络安全等级保护制度的要求，履行下列安全保护义务：（一）制定内部安全管理制度和操作规程，确定网络安全负责人，落实网络安全保护责任；（二）采取防范计算机病毒和网络攻击、网络侵入等危害网络安全行为的技术措施；（三）采取监测、记录网络运行状态、网络安全事件的技术措施，并按照规定留存相关的网络日志不少于六个月；（四）采取数据分类、重要数据备份和加密等措施。', '2026-03-08 14:18:53.738082', 408, 1957, b'1', 15, '{\"keywords\":[\"第二十一条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二十一条\",\"type\":\"ARTICLE_REF\"}]}', 1752, 'doc_408_seg_15', 'rule');
INSERT INTO `segments` VALUES (1518, '第一章 总则', '第四十一条 网络运营者收集、使用个人信息，应当遵循合法、正当、必要的原则，公开收集、使用规则，明示收集、使用信息的目的、方式和范围，并经被收集者同意。网络运营者不得收集与其提供的服务无关的个人信息，不得违反法律、行政法规的规定和双方的约定收集、使用个人信息，并应当依照法律、行政法规的规定和与用户的约定，处理其保存的个人信息。', '2026-03-08 14:18:53.739249', 408, 2120, b'1', 16, '{\"keywords\":[\"第四十一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四十一条\",\"type\":\"ARTICLE_REF\"}]}', 1957, 'doc_408_seg_16', 'rule');
INSERT INTO `segments` VALUES (1519, '第一章 总则', '第四十二条 网络运营者不得泄露、篡改、毁损其收集的个人信息；未经被收集者同意，不得向他人提供个人信息。但是，经过处理无法识别特定个人且不能复原的除外。', '2026-03-08 14:18:53.739249', 408, 2195, b'1', 17, '{\"keywords\":[\"第四十二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四十二条\",\"type\":\"ARTICLE_REF\"}]}', 2120, 'doc_408_seg_17', 'rule');
INSERT INTO `segments` VALUES (1520, '第一章 总则', '第四十四条 任何个人和组织不得窃取或者以其他非法方式获取个人信息，不得非法出售或者非法向他人提供个人信息。', '2026-03-08 14:18:53.740568', 408, 2248, b'1', 18, '{\"keywords\":[\"第四十四条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四十四条\",\"type\":\"ARTICLE_REF\"}]}', 2195, 'doc_408_seg_18', 'rule');
INSERT INTO `segments` VALUES (1521, '第一章 总则', '第六十四条 网络运营者、网络产品或者服务的提供者违反本法第二十二条第三款、第四十一条至第四十三条规定，侵害个人信息依法得到保护的权利的，由有关主管部门责令改正，可以根据情节单处或者并处警告、没收违法所得、处违法所得一倍以上十倍以下罚款，没有违法所得的，处一百万元以下罚款，对直接负责的主管人员和其他直接责任人员处一万元以上十万元以下罚款；情节严重的，并可以责令暂停相关业务、停业整顿、关闭网站、吊销相关业务许可证或者吊销营业执照。', '2026-03-08 14:18:53.740568', 408, 2463, b'1', 19, '{\"keywords\":[\"第六十四条\",\"第二十二条第三款\",\"第四十一条\",\"第四十三条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"MONEY\"],\"legal_entities\":[{\"text\":\"第六十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第二十二条第三款\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十一条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十三条\",\"type\":\"ARTICLE_REF\"}]}', 2248, 'doc_408_seg_19', 'rule');
INSERT INTO `segments` VALUES (1522, '第一章 刑法的任务、基本原则和适用范围', '第二条 中华人民共和国刑法的任务，是用刑罚同一切犯罪行为作斗争，以保卫国家安全，保卫人民民主专政的政权和社会主义制度，保护国有财产和劳动群众集体所有的财产，保护公民私人所有的财产，保护公民的人身权利、民主权利和其他权利，维护社会秩序、经济秩序，保障社会主义建设事业的顺利进行。', '2026-03-08 14:18:55.397198', 407, 230, b'1', 0, '{\"keywords\":[\"是用刑罚同一切犯罪\",\"第二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"是用刑罚同一切犯罪\",\"type\":\"CRIME\"},{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 92, 'doc_407_seg_0', 'semantic');
INSERT INTO `segments` VALUES (1523, '第一节 犯罪和刑事责任', '第十三条 一切危害国家主权、领土完整和安全，分裂国家、颠覆人民民主专政的政权和推翻社会主义制度，破坏社会秩序和经济秩序，侵犯国有财产或者劳动群众集体所有的财产，侵犯公民私人所有的财产，侵犯公民的人身权利、民主权利和其他权利，以及其他危害社会的行为，依照法律应当受刑罚处罚的，都是犯罪，但是情节显著轻微危害不大的，不认为是犯罪。', '2026-03-08 14:18:55.398599', 407, 534, b'1', 1, '{\"keywords\":[\"都是犯罪\",\"不认为是犯罪\",\"第十三条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"都是犯罪\",\"type\":\"CRIME\"},{\"text\":\"不认为是犯罪\",\"type\":\"CRIME\"},{\"text\":\"第十三条\",\"type\":\"ARTICLE_REF\"}]}', 371, 'doc_407_seg_1', 'semantic');
INSERT INTO `segments` VALUES (1524, '第一节 犯罪和刑事责任', '第十四条 明知自己的行为会发生危害社会的结果，并且希望或者放任这种结果发生，因而构成犯罪的，是故意犯罪。故意犯罪，应当负刑事责任。', '2026-03-08 14:18:55.399606', 407, 600, b'1', 2, '{\"keywords\":[\"因而构成犯罪\",\"是故意犯罪\",\"故意犯罪\",\"第十四条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"因而构成犯罪\",\"type\":\"CRIME\"},{\"text\":\"是故意犯罪\",\"type\":\"CRIME\"},{\"text\":\"故意犯罪\",\"type\":\"CRIME\"},{\"text\":\"第十四条\",\"type\":\"ARTICLE_REF\"}]}', 535, 'doc_407_seg_2', 'semantic');
INSERT INTO `segments` VALUES (1525, '第一节 犯罪和刑事责任', '第十五条 应当预见自己的行为可能发生危害社会的结果，因为疏忽大意而没有预见，或者已经预见而轻信能够避免，以致发生这种结果的，是过失犯罪。过失犯罪，法律有规定的才负刑事责任。', '2026-03-08 14:18:55.399606', 407, 687, b'1', 3, '{\"keywords\":[\"是过失犯罪\",\"过失犯罪\",\"第十五条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"是过失犯罪\",\"type\":\"CRIME\"},{\"text\":\"过失犯罪\",\"type\":\"CRIME\"},{\"text\":\"第十五条\",\"type\":\"ARTICLE_REF\"}]}', 601, 'doc_407_seg_3', 'semantic');
INSERT INTO `segments` VALUES (1526, '第一节 犯罪和刑事责任', '第十七条 已满十六周岁的人犯罪，应当负刑事责任。已满十四周岁不满十六周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。已满十二周岁不满十四周岁的人，犯故意杀人、故意伤害罪，致人死亡或者以特别残忍手段致人重伤造成严重残疾，情节恶劣，经最高人民检察院核准追诉的，应当负刑事责任。', '2026-03-08 14:18:55.401214', 407, 858, b'1', 4, '{\"keywords\":[\"满十六周岁的人犯罪\",\"投放危险物质罪\",\"故意伤害罪\",\"第十七条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"ORG\"],\"legal_entities\":[{\"text\":\"满十六周岁的人犯罪\",\"type\":\"CRIME\"},{\"text\":\"投放危险物质罪\",\"type\":\"CRIME\"},{\"text\":\"故意伤害罪\",\"type\":\"CRIME\"},{\"text\":\"第十七条\",\"type\":\"ARTICLE_REF\"}]}', 688, 'doc_407_seg_4', 'semantic');
INSERT INTO `segments` VALUES (1527, '第一节 犯罪和刑事责任', '第二十条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在进行的不法侵害，而采取的制止不法侵害的行为，对不法侵害人造成损害的，属于正当防卫，不负刑事责任。正当防卫明显超过必要限度造成重大损害的，应当负刑事责任，但是应当减轻或者免除处罚。对正在进行行凶、杀人、抢劫、强奸、绑架以及其他严重危及人身安全的暴力犯罪，采取防卫行为，造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。', '2026-03-08 14:18:55.402219', 407, 1055, b'1', 5, '{\"keywords\":[\"人身安全的暴力犯罪\",\"第二十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"人身安全的暴力犯罪\",\"type\":\"CRIME\"},{\"text\":\"第二十条\",\"type\":\"ARTICLE_REF\"}]}', 859, 'doc_407_seg_5', 'semantic');
INSERT INTO `segments` VALUES (1528, '第三章 刑罚', '第二十一条 为了使国家、公共利益、本人或者他人的人身、财产和其他权利免受正在发生的危险，不得已采取的紧急避险行为，造成损害的，不负刑事责任。紧急避险超过必要限度造成不应有的损害的，应当负刑事责任，但是应当减轻或者免除处罚。', '2026-03-08 14:18:55.403217', 407, 1167, b'1', 6, '{\"keywords\":[\"第二十一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十一条\",\"type\":\"ARTICLE_REF\"}]}', 1056, 'doc_407_seg_6', 'semantic');
INSERT INTO `segments` VALUES (1529, '第三章 刑罚', '第三十四条 附加刑的种类如下：（一）罚金；（二）剥夺政治权利；（三）没收财产。附加刑也可以独立适用。', '2026-03-08 14:18:55.403217', 407, 1274, b'1', 7, '{\"keywords\":[\"第三十四条\",\"罚金\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"PERSON\"],\"legal_entities\":[{\"text\":\"第三十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"}]}', 1224, 'doc_407_seg_7', 'semantic');
INSERT INTO `segments` VALUES (1530, '第三章 刑罚', '第四十八条 死刑只适用于罪行极其严重的犯罪分子。对于应当判处死刑的犯罪分子，如果不是必须立即执行的，可以判处死刑同时宣告缓期二年执行。', '2026-03-08 14:18:55.404497', 407, 1418, b'1', 8, '{\"keywords\":[\"死刑只适用于罪\",\"行极其严重的犯罪\",\"应当判处死刑的犯罪\",\"第四十八条\",\"死刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"死刑只适用于罪\",\"type\":\"CRIME\"},{\"text\":\"行极其严重的犯罪\",\"type\":\"CRIME\"},{\"text\":\"应当判处死刑的犯罪\",\"type\":\"CRIME\"},{\"text\":\"第四十八条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"死刑\",\"type\":\"PENALTY\"}]}', 1351, 'doc_407_seg_8', 'semantic');
INSERT INTO `segments` VALUES (1531, '第三章 刑罚', '第六十七条 犯罪以后自动投案，如实供述自己的罪行的，是自首。对于自首的犯罪分子，可以从轻或者减轻处罚。其中，犯罪较轻的，可以免除处罚。', '2026-03-08 14:18:55.404497', 407, 1486, b'1', 9, '{\"keywords\":[\"如实供述自己的罪\",\"对于自首的犯罪\",\"第六十七条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"如实供述自己的罪\",\"type\":\"CRIME\"},{\"text\":\"对于自首的犯罪\",\"type\":\"CRIME\"},{\"text\":\"第六十七条\",\"type\":\"ARTICLE_REF\"}]}', 1419, 'doc_407_seg_9', 'semantic');
INSERT INTO `segments` VALUES (1532, '第三章 刑罚', '第六十八条 犯罪分子有揭发他人犯罪行为，查证属实的，或者提供重要线索，从而得以侦破其他案件等立功表现的，可以从轻或者减轻处罚；有重大立功表现的，可以减轻或者免除处罚。', '2026-03-08 14:18:55.404497', 407, 1570, b'1', 10, '{\"keywords\":[\"分子有揭发他人犯罪\",\"第六十八条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"分子有揭发他人犯罪\",\"type\":\"CRIME\"},{\"text\":\"第六十八条\",\"type\":\"ARTICLE_REF\"}]}', 1487, 'doc_407_seg_10', 'semantic');
INSERT INTO `segments` VALUES (1533, '第三章 刑罚', '第七十二条 对于被判处拘役、三年以下有期徒刑的犯罪分子，同时符合下列条件的，可以宣告缓刑，对其中不满十八周岁的人、怀孕的妇女和已满七十五周岁的人，应当宣告缓刑：（一）犯罪情节较轻；（二）有悔罪表现；（三）没有再犯罪的危险；（四）宣告缓刑对所居住社区没有重大不良影响。', '2026-03-08 14:18:55.405712', 407, 1704, b'1', 11, '{\"keywords\":[\"以下有期徒刑的犯罪\",\"有悔罪\",\"没有再犯罪\",\"第七十二条\",\"拘役\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"以下有期徒刑的犯罪\",\"type\":\"CRIME\"},{\"text\":\"有悔罪\",\"type\":\"CRIME\"},{\"text\":\"没有再犯罪\",\"type\":\"CRIME\"},{\"text\":\"第七十二条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"}]}', 1571, 'doc_407_seg_11', 'semantic');
INSERT INTO `segments` VALUES (1534, '第四章 侵犯公民人身权利、民主权利罪', '第二百三十二条 故意杀人的，处死刑、无期徒刑或者十年以上有期徒刑；情节较轻的，处三年以上十年以下有期徒刑。', '2026-03-08 14:18:55.405712', 407, 1784, b'1', 12, '{\"keywords\":[\"第二百三十二条\",\"死刑\",\"无期徒刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百三十二条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"死刑\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"}]}', 1731, 'doc_407_seg_12', 'semantic');
INSERT INTO `segments` VALUES (1535, '第四章 侵犯公民人身权利、民主权利罪', '第二百三十四条 故意伤害他人身体的，处三年以下有期徒刑、拘役或者管制。犯前款罪，致人重伤的，处三年以上十年以下有期徒刑；致人死亡或者以特别残忍手段致人重伤造成严重残疾的，处十年以上有期徒刑、无期徒刑或者死刑。', '2026-03-08 14:18:55.406719', 407, 1936, b'1', 13, '{\"keywords\":[\"犯前款罪\",\"第二百三十四条\",\"拘役\",\"管制\",\"无期徒刑\",\"死刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"犯前款罪\",\"type\":\"CRIME\"},{\"text\":\"第二百三十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"},{\"text\":\"死刑\",\"type\":\"PENALTY\"}]}', 1832, 'doc_407_seg_13', 'semantic');
INSERT INTO `segments` VALUES (1536, '第四章 侵犯公民人身权利、民主权利罪', '第二百三十八条 非法拘禁他人或者以其他方法非法剥夺他人人身自由的，处三年以下有期徒刑、拘役、管制或者剥夺政治权利。具有殴打、侮辱情节的，从重处罚。', '2026-03-08 14:18:55.406719', 407, 2051, b'1', 14, '{\"keywords\":[\"第二百三十八条\",\"拘役\",\"管制\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百三十八条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"}]}', 1978, 'doc_407_seg_14', 'semantic');
INSERT INTO `segments` VALUES (1537, '第四章 侵犯公民人身权利、民主权利罪', '第二百四十条 拐卖妇女、儿童的，处五年以上十年以下有期徒刑，并处罚金；情节严重的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产；情节特别严重的，处死刑，并处没收财产。', '2026-03-08 14:18:55.407719', 407, 2139, b'1', 15, '{\"keywords\":[\"第二百四十条\",\"罚金\",\"无期徒刑\",\"死刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百四十条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"},{\"text\":\"死刑\",\"type\":\"PENALTY\"}]}', 2052, 'doc_407_seg_15', 'semantic');
INSERT INTO `segments` VALUES (1538, '第四章 侵犯公民人身权利、民主权利罪', '第二百四十六条 以暴力或者其他方法公然侮辱他人或者捏造事实诽谤他人，情节严重的，处三年以下有期徒刑、拘役、管制或者剥夺政治权利。', '2026-03-08 14:18:55.407719', 407, 2204, b'1', 16, '{\"keywords\":[\"第二百四十六条\",\"拘役\",\"管制\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百四十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"}]}', 2140, 'doc_407_seg_16', 'semantic');
INSERT INTO `segments` VALUES (1539, '第五章 侵犯财产罪', '第二百五十三条之一 违反国家有关规定，向他人出售或者提供公民个人信息，情节严重的，处三年以下有期徒刑或者拘役，并处或者单处罚金；情节特别严重的，处三年以上七年以下有期徒刑，并处罚金。', '2026-03-08 14:18:55.407719', 407, 2296, b'1', 17, '{\"keywords\":[\"第二百五十三条\",\"拘役\",\"罚金\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百五十三条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"}]}', 2205, 'doc_407_seg_17', 'semantic');
INSERT INTO `segments` VALUES (1540, '第五章 侵犯财产罪', '第二百六十三条 以暴力、胁迫或者其他方法抢劫公私财物的，处三年以上十年以下有期徒刑，并处罚金；有下列情形之一的，处十年以上有期徒刑、无期徒刑或者死刑，并处罚金或者没收财产：（一）入户抢劫的；（二）在公共交通工具上抢劫的；（三）抢劫银行或者其他金融机构的；（四）多次抢劫或者抢劫数额巨大的；（五）抢劫致人重伤、死亡的；（六）冒充军警人员抢劫的；（七）持枪抢劫的；（八）抢劫军用物资或者抢险、救灾、救济物资的。', '2026-03-08 14:18:55.408719', 407, 2510, b'1', 18, '{\"keywords\":[\"第二百六十三条\",\"罚金\",\"无期徒刑\",\"死刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二百六十三条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"},{\"text\":\"死刑\",\"type\":\"PENALTY\"}]}', 2307, 'doc_407_seg_18', 'semantic');
INSERT INTO `segments` VALUES (1541, '第五章 侵犯财产罪', '第二百六十四条 盗窃公私财物，数额较大的，或者多次盗窃、入户盗窃、携带凶器盗窃、扒窃的，处三年以下有期徒刑、拘役或者管制，并处或者单处罚金；数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金；数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产。', '2026-03-08 14:18:55.408719', 407, 2661, b'1', 19, '{\"keywords\":[\"第二百六十四条\",\"拘役\",\"管制\",\"罚金\",\"无期徒刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百六十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"}]}', 2511, 'doc_407_seg_19', 'semantic');
INSERT INTO `segments` VALUES (1542, '第五章 侵犯财产罪', '第二百六十六条 诈骗公私财物，数额较大的，处三年以下有期徒刑、拘役或者管制，并处或者单处罚金；数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金；数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产。', '2026-03-08 14:18:55.409719', 407, 2789, b'1', 20, '{\"keywords\":[\"第二百六十六条\",\"拘役\",\"管制\",\"罚金\",\"无期徒刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百六十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"}]}', 2662, 'doc_407_seg_20', 'semantic');
INSERT INTO `segments` VALUES (1543, '第五章 侵犯财产罪', '第二百七十条 将代为保管的他人财物非法占为己有，数额较大，拒不退还的，处二年以下有期徒刑、拘役或者罚金；数额巨大或者有其他严重情节的，处二年以上五年以下有期徒刑，并处罚金。将他人的遗忘物或者埋藏物非法占为己有，数额较大，拒不交出的，依照前款的规定处罚。', '2026-03-08 14:18:55.409719', 407, 2916, b'1', 21, '{\"keywords\":[\"第二百七十条\",\"拘役\",\"罚金\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百七十条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"}]}', 2790, 'doc_407_seg_21', 'semantic');
INSERT INTO `segments` VALUES (1544, '第六章 妨害社会管理秩序罪', '第二百七十四条 敲诈勒索公私财物，数额较大或者多次敲诈勒索的，处三年以下有期徒刑、拘役或者管制，并处或者单处罚金；数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金；数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑，并处罚金。', '2026-03-08 14:18:55.410721', 407, 3042, b'1', 22, '{\"keywords\":[\"第二百七十四条\",\"拘役\",\"管制\",\"罚金\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百七十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"}]}', 2917, 'doc_407_seg_22', 'semantic');
INSERT INTO `segments` VALUES (1545, '第六章 妨害社会管理秩序罪', '第二百九十一条之一 编造虚假的险情、疫情、灾情、警情，在信息网络或者其他媒体上传播，或者明知是上述虚假信息，故意在信息网络或者其他媒体上传播，严重扰乱社会秩序的，处三年以下有期徒刑、拘役或者管制；造成严重后果的，处三年以上七年以下有期徒刑。', '2026-03-08 14:18:55.411720', 407, 3177, b'1', 23, '{\"keywords\":[\"第二百九十一条\",\"拘役\",\"管制\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二百九十一条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"}]}', 3057, 'doc_407_seg_23', 'semantic');
INSERT INTO `segments` VALUES (1546, '第八章 贪污贿赂罪', '第二百九十三条 有下列寻衅滋事行为之一，破坏社会秩序的，处五年以下有期徒刑、拘役或者管制：（一）随意殴打他人，情节恶劣的；（二）追逐、拦截、辱骂、恐吓他人，情节恶劣的；（三）强拿硬要或者任意损毁、占用公私财物，情节严重的；（四）在公共场所起哄闹事，造成公共场所秩序严重混乱的。', '2026-03-08 14:18:55.411720', 407, 3316, b'1', 24, '{\"keywords\":[\"第二百九十三条\",\"拘役\",\"管制\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\",\"FAC\"],\"legal_entities\":[{\"text\":\"第二百九十三条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"管制\",\"type\":\"PENALTY\"}]}', 3178, 'doc_407_seg_24', 'semantic');
INSERT INTO `segments` VALUES (1547, '第八章 贪污贿赂罪', '第三百八十二条 国家工作人员利用职务上的便利，侵吞、窃取、骗取或者以其他手段非法占有公共财物的，是贪污罪。', '2026-03-08 14:18:55.411720', 407, 3380, b'1', 25, '{\"keywords\":[\"是贪污罪\",\"第三百八十二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"是贪污罪\",\"type\":\"CRIME\"},{\"text\":\"第三百八十二条\",\"type\":\"ARTICLE_REF\"}]}', 3327, 'doc_407_seg_25', 'semantic');
INSERT INTO `segments` VALUES (1548, '第八章 贪污贿赂罪', '第三百八十三条 对犯贪污罪的，根据情节轻重，分别依照下列规定处罚：贪污数额较大或者有其他较重情节的，处三年以下有期徒刑或者拘役，并处罚金。贪污数额巨大或者有其他严重情节的，处三年以上十年以下有期徒刑，并处罚金或者没收财产。贪污数额特别巨大或者有其他特别严重情节的，处十年以上有期徒刑或者无期徒刑，并处罚金或者没收财产；数额特别巨大，并使国家和人民利益遭受特别重大损失的，处无期徒刑或者死刑，并处没收财产。', '2026-03-08 14:18:55.411720', 407, 3583, b'1', 26, '{\"keywords\":[\"对犯贪污罪\",\"第三百八十三条\",\"拘役\",\"罚金\",\"无期徒刑\",\"死刑\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"对犯贪污罪\",\"type\":\"CRIME\"},{\"text\":\"第三百八十三条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"},{\"text\":\"罚金\",\"type\":\"PENALTY\"},{\"text\":\"无期徒刑\",\"type\":\"PENALTY\"},{\"text\":\"死刑\",\"type\":\"PENALTY\"}]}', 3381, 'doc_407_seg_26', 'semantic');
INSERT INTO `segments` VALUES (1549, '第八章 贪污贿赂罪', '第三百八十五条 国家工作人员利用职务上的便利，索取他人财物的，或者非法收受他人财物，为他人谋取利益的，是受贿罪。', '2026-03-08 14:18:55.413146', 407, 3640, b'1', 27, '{\"keywords\":[\"是受贿罪\",\"第三百八十五条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"是受贿罪\",\"type\":\"CRIME\"},{\"text\":\"第三百八十五条\",\"type\":\"ARTICLE_REF\"}]}', 3584, 'doc_407_seg_27', 'semantic');
INSERT INTO `segments` VALUES (1550, '第八章 贪污贿赂罪', '第三百九十七条 国家机关工作人员滥用职权或者玩忽职守，致使公共财产、国家和人民利益遭受重大损失的，处三年以下有期徒刑或者拘役；情节特别严重的，处三年以上七年以下有期徒刑。', '2026-03-08 14:18:55.413146', 407, 3762, b'1', 28, '{\"keywords\":[\"第三百九十七条\",\"拘役\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第三百九十七条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"拘役\",\"type\":\"PENALTY\"}]}', 3677, 'doc_407_seg_28', 'semantic');
INSERT INTO `segments` VALUES (1551, '第一章 基本规定', '第一条 为了保护民事主体的合法权益，调整民事关系，维护社会和经济秩序，适应中国特色社会主义发展要求，弘扬社会主义核心价值观，根据宪法，制定本法。', '2026-03-08 14:18:58.543851', 406, 72, b'1', 0, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\",\"GPE\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 0, 'doc_406_seg_0', 'paragraph');
INSERT INTO `segments` VALUES (1552, '第一节 民事权利能力和民事行为能力', '第十五条 自然人的出生时间和死亡时间，以出生证明、死亡证明记载的时间为准；没有出生证明、死亡证明的，以户籍登记或者其他有效身份登记记载的时间为准。有其他证据足以推翻以上记载时间的，以该证据证明的时间为准。', '2026-03-08 14:18:58.544858', 406, 175, b'1', 1, '{\"keywords\":[\"第十五条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十五条\",\"type\":\"ARTICLE_REF\"}]}', 73, 'doc_406_seg_1', 'paragraph');
INSERT INTO `segments` VALUES (1553, '第一节 民事权利能力和民事行为能力', '第十六条 涉及遗产继承、接受赠与等胎儿利益保护的，胎儿视为具有民事权利能力。但是，胎儿娩出时为死体的，其民事权利能力自始不存在。', '2026-03-08 14:18:58.544858', 406, 240, b'1', 2, '{\"keywords\":[\"第十六条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十六条\",\"type\":\"ARTICLE_REF\"}]}', 176, 'doc_406_seg_2', 'paragraph');
INSERT INTO `segments` VALUES (1554, '第一节 民事权利能力和民事行为能力', '第十八条 成年人为完全民事行为能力人，可以独立实施民事法律行为。十六周岁以上的未成年人，以自己的劳动收入为主要生活来源的，视为完全民事行为能力人。', '2026-03-08 14:18:58.545960', 406, 314, b'1', 3, '{\"keywords\":[\"第十八条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第十八条\",\"type\":\"ARTICLE_REF\"}]}', 241, 'doc_406_seg_3', 'paragraph');
INSERT INTO `segments` VALUES (1555, '第一节 民事权利能力和民事行为能力', '第十九条 八周岁以上的未成年人为限制民事行为能力人，实施民事法律行为由其法定代理人代理或者经其法定代理人同意、追认；但是，可以独立实施纯获利益的民事法律行为或者与其年龄、智力相适应的民事法律行为。', '2026-03-08 14:18:58.545960', 406, 413, b'1', 4, '{\"keywords\":[\"第十九条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第十九条\",\"type\":\"ARTICLE_REF\"}]}', 315, 'doc_406_seg_4', 'paragraph');
INSERT INTO `segments` VALUES (1556, '第一节 民事权利能力和民事行为能力', '第二十一条 不能辨认自己行为的成年人为无民事行为能力人，由其法定代理人代理实施民事法律行为。八周岁以上的未成年人不能辨认自己行为的，适用前款规定。', '2026-03-08 14:18:58.546965', 406, 487, b'1', 5, '{\"keywords\":[\"第二十一条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二十一条\",\"type\":\"ARTICLE_REF\"}]}', 414, 'doc_406_seg_5', 'paragraph');
INSERT INTO `segments` VALUES (1557, '第一节 民事权利能力和民事行为能力', '第二十二条 不能完全辨认自己行为的成年人为限制民事行为能力人，实施民事法律行为由其法定代理人代理或者经其法定代理人同意、追认；但是，可以独立实施纯获利益的民事法律行为或者与其智力、精神健康状况相适应的民事法律行为。', '2026-03-08 14:18:58.546965', 406, 595, b'1', 6, '{\"keywords\":[\"第二十二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十二条\",\"type\":\"ARTICLE_REF\"}]}', 488, 'doc_406_seg_6', 'paragraph');
INSERT INTO `segments` VALUES (1558, '第二节 监护', '第二十七条 父母是未成年子女的监护人。未成年人的父母已经死亡或者没有监护能力的，由下列有监护能力的人按顺序担任监护人：（一）祖父母、外祖父母；（二）兄、姐；（三）其他愿意担任监护人的个人或者组织，但是须经未成年人住所地的居民委员会、村民委员会或者民政部门同意。', '2026-03-08 14:18:58.546965', 406, 726, b'1', 7, '{\"keywords\":[\"第二十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十七条\",\"type\":\"ARTICLE_REF\"}]}', 596, 'doc_406_seg_7', 'paragraph');
INSERT INTO `segments` VALUES (1559, '第二节 监护', '第二十八条 无民事行为能力或者限制民事行为能力的成年人，由下列有监护能力的人按顺序担任监护人：（一）配偶；（二）父母、子女；（三）其他近亲属；（四）其他愿意担任监护人的个人或者组织，但是须经该成年人住所地的居民委员会、村民委员会或者民政部门同意。', '2026-03-08 14:18:58.548123', 406, 850, b'1', 8, '{\"keywords\":[\"第二十八条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十八条\",\"type\":\"ARTICLE_REF\"}]}', 727, 'doc_406_seg_8', 'paragraph');
INSERT INTO `segments` VALUES (1560, '第一节 一般规定', '第五十八条 法人应当依法成立。法人应当有自己的名称、组织机构、住所、财产或者经费。法人成立的具体条件和程序，依照法律、行政法规的规定。设立法人，法律、行政法规规定须经有关机关批准的，依照其规定。', '2026-03-08 14:18:58.548123', 406, 948, b'1', 9, '{\"keywords\":[\"第五十八条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五十八条\",\"type\":\"ARTICLE_REF\"}]}', 851, 'doc_406_seg_9', 'paragraph');
INSERT INTO `segments` VALUES (1561, '第一节 一般规定', '第六十一条 依照法律或者法人章程的规定，代表法人从事民事活动的负责人，为法人的法定代表人。法定代表人以法人名义从事的民事活动，其法律后果由法人承受。法人章程或者法人权力机构对法定代表人代表权的限制，不得对抗善意相对人。', '2026-03-08 14:18:58.549165', 406, 1058, b'1', 10, '{\"keywords\":[\"第六十一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第六十一条\",\"type\":\"ARTICLE_REF\"}]}', 949, 'doc_406_seg_10', 'paragraph');
INSERT INTO `segments` VALUES (1562, '第一节 一般规定', '第一百三十四条 民事法律行为可以基于双方或者多方的意思表示一致成立，也可以基于单方的意思表示成立。法人、非法人组织依照法律或者章程规定的议事方式和表决程序作出决议的，该决议行为成立。', '2026-03-08 14:18:58.549165', 406, 1150, b'1', 11, '{\"keywords\":[\"第一百三十四条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\"],\"legal_entities\":[{\"text\":\"第一百三十四条\",\"type\":\"ARTICLE_REF\"}]}', 1059, 'doc_406_seg_11', 'paragraph');
INSERT INTO `segments` VALUES (1563, '第一节 一般规定', '第一百三十五条 民事法律行为可以采用书面形式、口头形式或者其他形式；法律、行政法规规定或者当事人约定采用特定形式的，应当采用特定形式。', '2026-03-08 14:18:58.549165', 406, 1218, b'1', 12, '{\"keywords\":[\"第一百三十五条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"第一百三十五条\",\"type\":\"ARTICLE_REF\"}]}', 1151, 'doc_406_seg_12', 'paragraph');
INSERT INTO `segments` VALUES (1564, '第一节 一般规定', '第一百四十三条 具备下列条件的民事法律行为有效：（一）行为人具有相应的民事行为能力；（二）意思表示真实；（三）不违反法律、行政法规的强制性规定，不违背公序良俗。', '2026-03-08 14:18:58.550503', 406, 1299, b'1', 13, '{\"keywords\":[\"第一百四十三条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一百四十三条\",\"type\":\"ARTICLE_REF\"}]}', 1219, 'doc_406_seg_13', 'paragraph');
INSERT INTO `segments` VALUES (1565, '第一节 一般规定', '第一百四十六条 行为人与相对人以虚假的意思表示实施的民事法律行为无效。以虚假的意思表示隐藏的民事法律行为的效力，依照有关法律规定处理。', '2026-03-08 14:18:58.550503', 406, 1367, b'1', 14, '{\"keywords\":[\"第一百四十六条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"第一百四十六条\",\"type\":\"ARTICLE_REF\"}]}', 1300, 'doc_406_seg_14', 'paragraph');
INSERT INTO `segments` VALUES (1566, '第一节 一般规定', '第一百四十八条 一方以欺诈手段，使对方在违背真实意思的情况下实施的民事法律行为，受欺诈方有权请求人民法院或者仲裁机构予以撤销。', '2026-03-08 14:18:58.551509', 406, 1431, b'1', 15, '{\"keywords\":[\"第一百四十八条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"第一百四十八条\",\"type\":\"ARTICLE_REF\"}]}', 1368, 'doc_406_seg_15', 'paragraph');
INSERT INTO `segments` VALUES (1567, '第一节 一般规定', '第一百五十条 一方或者第三人以胁迫手段，使对方在违背真实意思的情况下实施的民事法律行为，受胁迫方有权请求人民法院或者仲裁机构予以撤销。', '2026-03-08 14:18:58.551509', 406, 1499, b'1', 16, '{\"keywords\":[\"第一百五十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一百五十条\",\"type\":\"ARTICLE_REF\"}]}', 1432, 'doc_406_seg_16', 'paragraph');
INSERT INTO `segments` VALUES (1568, '第一节 一般规定', '第一百五十三条 违反法律、行政法规的强制性规定的民事法律行为无效。但是，该强制性规定不导致该民事法律行为无效的除外。违背公序良俗的民事法律行为无效。', '2026-03-08 14:18:58.551509', 406, 1574, b'1', 17, '{\"keywords\":[\"第一百五十三条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"第一百五十三条\",\"type\":\"ARTICLE_REF\"}]}', 1500, 'doc_406_seg_17', 'paragraph');
INSERT INTO `segments` VALUES (1569, '第五章 民事权利', '第一百一十条 自然人享有生命权、身体权、健康权、姓名权、肖像权、名誉权、荣誉权、隐私权、婚姻自主权等权利。法人、非法人组织享有名称权、名誉权和荣誉权。', '2026-03-08 14:18:58.551509', 406, 1650, b'1', 18, '{\"keywords\":[\"第一百一十条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\",\"PERSON\"],\"legal_entities\":[{\"text\":\"第一百一十条\",\"type\":\"ARTICLE_REF\"}]}', 1575, 'doc_406_seg_18', 'paragraph');
INSERT INTO `segments` VALUES (1570, '第五章 民事权利', '第一百一十一条 自然人的个人信息受法律保护。任何组织或者个人需要获取他人个人信息的，应当依法取得并确保信息安全，不得非法收集、使用、加工、传输他人个人信息，不得非法买卖、提供或者公开他人个人信息。', '2026-03-08 14:18:58.552509', 406, 1749, b'1', 19, '{\"keywords\":[\"第一百一十一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一百一十一条\",\"type\":\"ARTICLE_REF\"}]}', 1651, 'doc_406_seg_19', 'paragraph');
INSERT INTO `segments` VALUES (1571, '第五章 民事权利', '第一百一十四条 民事主体依法享有物权。物权是权利人依法对特定的物享有直接支配和排他的权利，包括所有权、用益物权和担保物权。', '2026-03-08 14:18:58.552509', 406, 1811, b'1', 20, '{\"keywords\":[\"第一百一十四条\"],\"entity_labels\":[\"ORDINAL\",\"PERSON\"],\"legal_entities\":[{\"text\":\"第一百一十四条\",\"type\":\"ARTICLE_REF\"}]}', 1750, 'doc_406_seg_20', 'paragraph');
INSERT INTO `segments` VALUES (1572, '第五章 民事权利', '第一百一十八条 民事主体依法享有债权。债权是因合同、侵权行为、无因管理、不当得利以及法律的其他规定，权利人请求特定义务人为或者不为一定行为的权利。', '2026-03-08 14:18:58.553830', 406, 1885, b'1', 21, '{\"keywords\":[\"第一百一十八条\"],\"entity_labels\":[\"ORDINAL\",\"PERSON\"],\"legal_entities\":[{\"text\":\"第一百一十八条\",\"type\":\"ARTICLE_REF\"}]}', 1812, 'doc_406_seg_21', 'paragraph');
INSERT INTO `segments` VALUES (1573, '第六章 民事责任', '第一百七十九条 承担民事责任的方式主要有：（一）停止侵害；（二）排除妨碍；（三）消除危险；（四）返还财产；（五）恢复原状；（六）修理、重作、更换；（七）继续履行；（八）赔偿损失；（九）支付违约金；（十）消除影响、恢复名誉；（十一）赔礼道歉。法律规定惩罚性赔偿的，依照其规定。本条规定的承担民事责任的方式，可以单独适用，也可以合并适用。', '2026-03-08 14:18:58.553830', 406, 2053, b'1', 22, '{\"keywords\":[\"第一百七十九条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一百七十九条\",\"type\":\"ARTICLE_REF\"}]}', 1886, 'doc_406_seg_22', 'paragraph');
INSERT INTO `segments` VALUES (1574, '第六章 民事责任', '第一百八十八条 向人民法院请求保护民事权利的诉讼时效期间为三年。法律另有规定的，依照其规定。诉讼时效期间自权利人知道或者应当知道权利受到损害以及义务人之日起计算。法律另有规定的，依照其规定。但是，自权利受到损害之日起超过二十年的，人民法院不予保护，有特殊情况的，人民法院可以根据权利人的申请决定延长。', '2026-03-08 14:18:58.554862', 406, 2204, b'1', 23, '{\"keywords\":[\"第一百八十八条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"PERSON\",\"GPE\",\"ORG\"],\"legal_entities\":[{\"text\":\"第一百八十八条\",\"type\":\"ARTICLE_REF\"}]}', 2054, 'doc_406_seg_23', 'paragraph');
INSERT INTO `segments` VALUES (1575, '第一章 总则', '第一条 为了保护劳动者的合法权益，调整劳动关系，建立和维护适应社会主义市场经济的劳动制度，促进经济发展和社会进步，根据宪法，制定本法。', '2026-03-08 14:19:00.601719', 405, 67, b'1', 0, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 0, 'doc_405_seg_0', 'rule');
INSERT INTO `segments` VALUES (1576, '第一章 总则', '第二条 在中华人民共和国境内的企业、个体经济组织和与之形成劳动关系的劳动者，适用本法。国家机关、事业组织、社会团体和与之建立劳动合同关系的劳动者，依照本法执行。', '2026-03-08 14:19:00.602911', 405, 147, b'1', 1, '{\"keywords\":[\"第二条\"],\"entity_labels\":[\"ORDINAL\",\"GPE\"],\"legal_entities\":[{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 67, 'doc_405_seg_1', 'rule');
INSERT INTO `segments` VALUES (1577, '第二章 劳动合同和集体合同', '第三条 劳动者享有平等就业和选择职业的权利、取得劳动报酬的权利、休息休假的权利、获得劳动安全卫生保护的权利、接受职业技能培训的权利、享受社会保险和福利的权利、提请劳动争议处理的权利以及法律规定的其他劳动权利。', '2026-03-08 14:19:00.602911', 405, 251, b'1', 2, '{\"keywords\":[\"第三条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第三条\",\"type\":\"ARTICLE_REF\"}]}', 147, 'doc_405_seg_2', 'rule');
INSERT INTO `segments` VALUES (1578, '第二章 劳动合同和集体合同', '第十六条 劳动合同是劳动者与用人单位确立劳动关系、明确双方权利和义务的协议。建立劳动关系应当订立劳动合同。', '2026-03-08 14:19:00.604153', 405, 304, b'1', 3, '{\"keywords\":[\"第十六条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十六条\",\"type\":\"ARTICLE_REF\"}]}', 251, 'doc_405_seg_3', 'rule');
INSERT INTO `segments` VALUES (1579, '第二章 劳动合同和集体合同', '第十七条 订立和变更劳动合同，应当遵循平等自愿、协商一致的原则，不得违反法律、行政法规的规定。劳动合同依法订立即具有法律约束力，当事人必须履行劳动合同规定的义务。', '2026-03-08 14:19:00.604153', 405, 385, b'1', 4, '{\"keywords\":[\"第十七条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十七条\",\"type\":\"ARTICLE_REF\"}]}', 304, 'doc_405_seg_4', 'rule');
INSERT INTO `segments` VALUES (1580, '第二章 劳动合同和集体合同', '第十九条 劳动合同应当以书面形式订立，并具备以下条款：（一）劳动合同期限；（二）工作内容；（三）劳动保护和劳动条件；（四）劳动报酬；（五）劳动纪律；（六）劳动合同终止的条件；（七）违反劳动合同的责任。', '2026-03-08 14:19:00.605159', 405, 485, b'1', 5, '{\"keywords\":[\"第十九条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第十九条\",\"type\":\"ARTICLE_REF\"}]}', 385, 'doc_405_seg_5', 'rule');
INSERT INTO `segments` VALUES (1581, '第二章 劳动合同和集体合同', '第二十五条 劳动者有下列情形之一的，用人单位可以解除劳动合同：（一）在试用期间被证明不符合录用条件的；（二）严重违反劳动纪律或者用人单位规章制度的；（三）严重失职，营私舞弊，对用人单位利益造成重大损害的；（四）被依法追究刑事责任的。', '2026-03-08 14:19:00.605159', 405, 601, b'1', 6, '{\"keywords\":[\"第二十五条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十五条\",\"type\":\"ARTICLE_REF\"}]}', 485, 'doc_405_seg_6', 'rule');
INSERT INTO `segments` VALUES (1582, '第二章 劳动合同和集体合同', '第二十六条 有下列情形之一的，用人单位可以解除劳动合同，但是应当提前三十日以书面形式通知劳动者本人：（一）劳动者患病或者非因工负伤，医疗期满后，不能从事原工作也不能从事由用人单位另行安排的工作的；（二）劳动者不能胜任工作，经过培训或者调整工作岗位，仍不能胜任工作的；（三）劳动合同订立时所依据的客观情况发生重大变化，致使原劳动合同无法履行，经当事人协商不能就变更劳动合同达成协议的。', '2026-03-08 14:19:00.605159', 405, 792, b'1', 7, '{\"keywords\":[\"第二十六条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十六条\",\"type\":\"ARTICLE_REF\"}]}', 601, 'doc_405_seg_7', 'rule');
INSERT INTO `segments` VALUES (1583, '第三章 工资', '第二十九条 劳动者有下列情形之一的，用人单位不得依据本法第二十六条、第二十七条的规定解除劳动合同：（一）患职业病或者因工负伤并被确认丧失或者部分丧失劳动能力的；（二）患病或者负伤，在规定的医疗期内的；（三）女职工在孕期、产期、哺乳期内的；（四）法律、行政法规规定的其他情形。', '2026-03-08 14:19:00.606431', 405, 929, b'1', 8, '{\"keywords\":[\"第二十九条\",\"第二十六条\",\"第二十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十九条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第二十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第二十七条\",\"type\":\"ARTICLE_REF\"}]}', 792, 'doc_405_seg_8', 'rule');
INSERT INTO `segments` VALUES (1584, '第三章 工资', '第四十六条 工资分配应当遵循按劳分配原则，实行同工同酬。工资水平在经济发展的基础上逐步提高。国家对工资总量实行宏观调控。', '2026-03-08 14:19:00.606431', 405, 989, b'1', 9, '{\"keywords\":[\"第四十六条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四十六条\",\"type\":\"ARTICLE_REF\"}]}', 929, 'doc_405_seg_9', 'rule');
INSERT INTO `segments` VALUES (1585, '第三章 工资', '第四十八条 国家实行最低工资保障制度。最低工资的具体标准由省、自治区、直辖市人民政府规定，报国务院备案。用人单位支付劳动者的工资不得低于当地最低工资标准。', '2026-03-08 14:19:00.607439', 405, 1066, b'1', 10, '{\"keywords\":[\"第四十八条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\"],\"legal_entities\":[{\"text\":\"第四十八条\",\"type\":\"ARTICLE_REF\"}]}', 989, 'doc_405_seg_10', 'rule');
INSERT INTO `segments` VALUES (1586, '第四章 工作时间和休息休假', '第四十一条 用人单位由于生产经营需要，经与工会和劳动者协商后可以延长工作时间，一般每日不得超过一小时；因特殊原因需要延长工作时间的，在保障劳动者身体健康的条件下延长工作时间每日不得超过三小时，但是每月不得超过三十六小时。', '2026-03-08 14:19:00.607439', 405, 1176, b'1', 11, '{\"keywords\":[\"第四十一条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\",\"TIME\",\"DATE\"],\"legal_entities\":[{\"text\":\"第四十一条\",\"type\":\"ARTICLE_REF\"}]}', 1066, 'doc_405_seg_11', 'rule');
INSERT INTO `segments` VALUES (1587, '第一章 总则', '第四十四条 有下列情形之一的，用人单位应当按照下列标准支付高于劳动者正常工作时间工资的工资报酬：（一）安排劳动者延长工作时间的，支付不低于工资的百分之一百五十的工资报酬；（二）休息日安排劳动者工作又不能安排补休的，支付不低于工资的百分之二百的工资报酬；（三）法定休假日安排劳动者工作的，支付不低于工资的百分之三百的工资报酬。\n第二部分 劳动合同法', '2026-03-08 14:19:00.607439', 405, 1349, b'1', 12, '{\"keywords\":[\"第四十四条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第四十四条\",\"type\":\"ARTICLE_REF\"}]}', 1176, 'doc_405_seg_12', 'rule');
INSERT INTO `segments` VALUES (1588, '第一章 总则', '第一条 为了完善劳动合同制度，明确劳动合同双方当事人的权利和义务，保护劳动者的合法权益，构建和发展和谐稳定的劳动关系，制定本法。', '2026-03-08 14:19:00.608540', 405, 1413, b'1', 13, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 1349, 'doc_405_seg_13', 'rule');
INSERT INTO `segments` VALUES (1589, '第二章 劳动合同的订立', '第二条 中华人民共和国境内的企业、个体经济组织、民办非企业单位等组织与劳动者建立劳动关系，订立、履行、变更、解除或者终止劳动合同，适用本法。', '2026-03-08 14:19:00.608540', 405, 1483, b'1', 14, '{\"keywords\":[\"第二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 1413, 'doc_405_seg_14', 'rule');
INSERT INTO `segments` VALUES (1590, '第二章 劳动合同的订立', '第十条 建立劳动关系，应当订立书面劳动合同。已建立劳动关系，未同时订立书面劳动合同的，应当自用工之日起一个月内订立书面劳动合同。', '2026-03-08 14:19:00.609545', 405, 1547, b'1', 15, '{\"keywords\":[\"第十条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第十条\",\"type\":\"ARTICLE_REF\"}]}', 1483, 'doc_405_seg_15', 'rule');
INSERT INTO `segments` VALUES (1591, '第二章 劳动合同的订立', '第十四条 无固定期限劳动合同，是指用人单位与劳动者约定无确定终止时间的劳动合同。有下列情形之一，劳动者提出或者同意续订、订立劳动合同的，除劳动者提出订立固定期限劳动合同外，应当订立无固定期限劳动合同：（一）劳动者在该用人单位连续工作满十年的；（二）用人单位初次实行劳动合同制度或者国有企业改制重新订立劳动合同时，劳动者在该用人单位连续工作满十年且距法定退休年龄不足十年的；（三）连续订立二次固定期限劳动合同，且劳动者没有本法第三十九条和第四十条第一项、第二项规定的情形，续订劳动合同的。', '2026-03-08 14:19:00.609545', 405, 1790, b'1', 16, '{\"keywords\":[\"第十四条\",\"第三十九条\",\"第四十条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第三十九条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十条\",\"type\":\"ARTICLE_REF\"}]}', 1547, 'doc_405_seg_16', 'rule');
INSERT INTO `segments` VALUES (1592, '第二章 劳动合同的订立', '第十九条 劳动合同期限三个月以上不满一年的，试用期不得超过一个月；劳动合同期限一年以上不满三年的，试用期不得超过二个月；三年以上固定期限和无固定期限的劳动合同，试用期不得超过六个月。同一用人单位与同一劳动者只能约定一次试用期。', '2026-03-08 14:19:00.609545', 405, 1903, b'1', 17, '{\"keywords\":[\"第十九条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第十九条\",\"type\":\"ARTICLE_REF\"}]}', 1790, 'doc_405_seg_17', 'rule');
INSERT INTO `segments` VALUES (1593, '第二章 劳动合同的订立', '第二十条 劳动者在试用期的工资不得低于本单位相同岗位最低档工资或者劳动合同约定工资的百分之八十，并不得低于用人单位所在地的最低工资标准。', '2026-03-08 14:19:00.610546', 405, 1971, b'1', 18, '{\"keywords\":[\"第二十条\"],\"entity_labels\":[\"ORDINAL\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"第二十条\",\"type\":\"ARTICLE_REF\"}]}', 1903, 'doc_405_seg_18', 'rule');
INSERT INTO `segments` VALUES (1594, '第二章 劳动合同的订立', '第二十二条 用人单位为劳动者提供专项培训费用，对其进行专业技术培训的，可以与该劳动者订立协议，约定服务期。劳动者违反服务期约定的，应当按照约定向用人单位支付违约金。违约金的数额不得超过用人单位提供的培训费用。', '2026-03-08 14:19:00.610546', 405, 2075, b'1', 19, '{\"keywords\":[\"第二十二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十二条\",\"type\":\"ARTICLE_REF\"}]}', 1971, 'doc_405_seg_19', 'rule');
INSERT INTO `segments` VALUES (1595, '第二章 劳动合同的订立', '第二十三条 用人单位与劳动者可以在劳动合同中约定保守用人单位的商业秘密和与知识产权相关的保密事项。对负有保密义务的劳动者，用人单位可以在劳动合同或者保密协议中与劳动者约定竞业限制条款，并约定在解除或者终止劳动合同后，在竞业限制期限内按月给予劳动者经济补偿。', '2026-03-08 14:19:00.610546', 405, 2203, b'1', 20, '{\"keywords\":[\"第二十三条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十三条\",\"type\":\"ARTICLE_REF\"}]}', 2075, 'doc_405_seg_20', 'rule');
INSERT INTO `segments` VALUES (1596, '第三章 劳动合同的解除和终止', '第二十四条 竞业限制的人员限于用人单位的高级管理人员、高级技术人员和其他负有保密义务的人员。竞业限制的范围、地域、期限由用人单位与劳动者约定，竞业限制的约定不得违反法律、法规的规定。在解除或者终止劳动合同后，前款规定的人员到与本单位生产或者经营同类产品、从事同类业务的有竞争关系的其他用人单位，或者自己开业生产或者经营同类产品、从事同类业务的竞业限制期限，不得超过二年。', '2026-03-08 14:19:00.611546', 405, 2388, b'1', 21, '{\"keywords\":[\"第二十四条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第二十四条\",\"type\":\"ARTICLE_REF\"}]}', 2203, 'doc_405_seg_21', 'rule');
INSERT INTO `segments` VALUES (1597, '第三章 劳动合同的解除和终止', '第三十七条 劳动者提前三十日以书面形式通知用人单位，可以解除劳动合同。劳动者在试用期内提前三日通知用人单位，可以解除劳动合同。', '2026-03-08 14:19:00.611546', 405, 2451, b'1', 22, '{\"keywords\":[\"第三十七条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第三十七条\",\"type\":\"ARTICLE_REF\"}]}', 2388, 'doc_405_seg_22', 'rule');
INSERT INTO `segments` VALUES (1598, '第三章 劳动合同的解除和终止', '第三十八条 用人单位有下列情形之一的，劳动者可以解除劳动合同：（一）未按照劳动合同约定提供劳动保护或者劳动条件的；（二）未及时足额支付劳动报酬的；（三）未依法为劳动者缴纳社会保险费的；（四）用人单位的规章制度违反法律、法规的规定，损害劳动者权益的；（五）因本法第二十六条第一款规定的情形致使劳动合同无效的；（六）法律、行政法规规定劳动者可以解除劳动合同的其他情形。', '2026-03-08 14:19:00.612548', 405, 2633, b'1', 23, '{\"keywords\":[\"第三十八条\",\"第二十六条第一款\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第三十八条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第二十六条第一款\",\"type\":\"ARTICLE_REF\"}]}', 2451, 'doc_405_seg_23', 'rule');
INSERT INTO `segments` VALUES (1599, '第三章 劳动合同的解除和终止', '第四十六条 有下列情形之一的，用人单位应当向劳动者支付经济补偿：（一）劳动者依照本法第三十八条规定解除劳动合同的；（二）用人单位依照本法第三十六条规定向劳动者提出解除劳动合同并与劳动者协商一致解除劳动合同的；（三）用人单位依照本法第四十条规定解除劳动合同的；（四）用人单位依照本法第四十一条第一款规定解除劳动合同的。', '2026-03-08 14:19:00.612548', 405, 2791, b'1', 24, '{\"keywords\":[\"第四十六条\",\"第三十八条\",\"第三十六条\",\"第四十条\",\"第四十一条第一款\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第四十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第三十八条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第三十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十一条第一款\",\"type\":\"ARTICLE_REF\"}]}', 2633, 'doc_405_seg_24', 'rule');
INSERT INTO `segments` VALUES (1600, '第三章 劳动合同的解除和终止', '第四十七条 经济补偿按劳动者在本单位工作的年限，每满一年支付一个月工资的标准向劳动者支付。六个月以上不满一年的，按一年计算；不满六个月的，向劳动者支付半个月工资的经济补偿。劳动者月工资高于用人单位所在直辖市、设区的市级人民政府公布的本地区上年度职工月平均工资三倍的，向其支付经济补偿的标准按职工月平均工资三倍的数额支付，向其支付经济补偿的年限最高不超过十二年。', '2026-03-08 14:19:00.613543', 405, 2971, b'1', 25, '{\"keywords\":[\"第四十七条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\",\"FAC\"],\"legal_entities\":[{\"text\":\"第四十七条\",\"type\":\"ARTICLE_REF\"}]}', 2791, 'doc_405_seg_25', 'rule');
INSERT INTO `segments` VALUES (1601, '第三章 劳动合同的解除和终止', '第八十二条 用人单位自用工之日起超过一个月不满一年未与劳动者订立书面劳动合同的，应当向劳动者每月支付二倍的工资。', '2026-03-08 14:19:00.613543', 405, 3027, b'1', 26, '{\"keywords\":[\"第八十二条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第八十二条\",\"type\":\"ARTICLE_REF\"}]}', 2971, 'doc_405_seg_26', 'rule');
INSERT INTO `segments` VALUES (1602, '第三章 劳动合同的解除和终止', '第八十七条 用人单位违反本法规定解除或者终止劳动合同的，应当依照本法第四十七条规定的经济补偿标准的二倍向劳动者支付赔偿金。', '2026-03-08 14:19:00.613543', 405, 3088, b'1', 27, '{\"keywords\":[\"第八十七条\",\"第四十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第八十七条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十七条\",\"type\":\"ARTICLE_REF\"}]}', 3027, 'doc_405_seg_27', 'rule');
INSERT INTO `segments` VALUES (1603, '第一章 总则', '第一条 为了维护道路交通秩序，预防和减少交通事故，保护人身安全，保护公民、法人和其他组织的财产安全及其他合法权益，提高通行效率，制定本法。', '2026-03-08 14:19:01.294388', 404, 69, b'1', 0, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 0, 'doc_404_seg_0', 'paragraph');
INSERT INTO `segments` VALUES (1604, '第一章 总则', '第二条 中华人民共和国境内的车辆驾驶人、行人、乘车人以及与道路交通活动有关的单位和个人，都应当遵守本法。', '2026-03-08 14:19:01.295885', 404, 122, b'1', 1, '{\"keywords\":[\"第二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 70, 'doc_404_seg_1', 'paragraph');
INSERT INTO `segments` VALUES (1605, '第二章 车辆和驾驶人', '第八条 国家对机动车实行登记制度。机动车经公安机关交通管理部门登记后，方可上道路行驶。尚未登记的机动车，需要临时上道路行驶的，应当取得临时通行牌证。', '2026-03-08 14:19:01.296905', 404, 197, b'1', 2, '{\"keywords\":[\"第八条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第八条\",\"type\":\"ARTICLE_REF\"}]}', 123, 'doc_404_seg_2', 'paragraph');
INSERT INTO `segments` VALUES (1606, '第二章 车辆和驾驶人', '第十九条 驾驶机动车，应当依法取得机动车驾驶证。申请机动车驾驶证，应当符合国务院公安部门规定的驾驶许可条件；经考试合格后，由公安机关交通管理部门发给相应类别的机动车驾驶证。', '2026-03-08 14:19:01.296905', 404, 284, b'1', 3, '{\"keywords\":[\"第十九条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\"],\"legal_entities\":[{\"text\":\"第十九条\",\"type\":\"ARTICLE_REF\"}]}', 198, 'doc_404_seg_3', 'paragraph');
INSERT INTO `segments` VALUES (1607, '第二章 车辆和驾驶人', '第二十二条 机动车驾驶人应当遵守道路交通安全法律、法规的规定，按照操作规范安全驾驶、文明驾驶。饮酒、服用国家管制的精神药品或者麻醉药品，或者患有妨碍安全驾驶机动车的疾病，或者过度疲劳影响安全驾驶的，不得驾驶机动车。', '2026-03-08 14:19:01.297905', 404, 392, b'1', 4, '{\"keywords\":[\"第二十二条\",\"管制\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十二条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"管制\",\"type\":\"PENALTY\"}]}', 285, 'doc_404_seg_4', 'paragraph');
INSERT INTO `segments` VALUES (1608, '第三章 道路通行条件', '第二十五条 全国实行统一的道路交通信号。交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥。', '2026-03-08 14:19:01.297905', 404, 443, b'1', 5, '{\"keywords\":[\"第二十五条\"],\"entity_labels\":[\"ORDINAL\",\"ORG\"],\"legal_entities\":[{\"text\":\"第二十五条\",\"type\":\"ARTICLE_REF\"}]}', 393, 'doc_404_seg_5', 'paragraph');
INSERT INTO `segments` VALUES (1609, '第四章 道路通行规定', '第四十二条 机动车上道路行驶，不得超过限速标志标明的最高时速。在没有限速标志的路段，应当保持安全车速。', '2026-03-08 14:19:01.298900', 404, 495, b'1', 6, '{\"keywords\":[\"第四十二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四十二条\",\"type\":\"ARTICLE_REF\"}]}', 444, 'doc_404_seg_6', 'paragraph');
INSERT INTO `segments` VALUES (1610, '第四章 道路通行规定', '第四十七条 机动车行经人行横道时，应当减速行驶；遇行人正在通过人行横道，应当停车让行。机动车行经没有交通信号的道路时，遇行人横过道路，应当避让。', '2026-03-08 14:19:01.298900', 404, 568, b'1', 7, '{\"keywords\":[\"第四十七条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四十七条\",\"type\":\"ARTICLE_REF\"}]}', 496, 'doc_404_seg_7', 'paragraph');
INSERT INTO `segments` VALUES (1611, '第四章 道路通行规定', '第五十一条 机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。', '2026-03-08 14:19:01.298900', 404, 623, b'1', 8, '{\"keywords\":[\"第五十一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五十一条\",\"type\":\"ARTICLE_REF\"}]}', 569, 'doc_404_seg_8', 'paragraph');
INSERT INTO `segments` VALUES (1612, '第四章 道路通行规定', '第七十条 在道路上发生交通事故，车辆驾驶人应当立即停车，保护现场；造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门。', '2026-03-08 14:19:01.300209', 404, 706, b'1', 9, '{\"keywords\":[\"第七十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第七十条\",\"type\":\"ARTICLE_REF\"}]}', 624, 'doc_404_seg_9', 'paragraph');
INSERT INTO `segments` VALUES (1613, '第四章 道路通行规定', '第七十六条 机动车发生交通事故造成人身伤亡、财产损失的，由保险公司在机动车第三者责任强制保险责任限额范围内予以赔偿；不足的部分，按照下列规定承担赔偿责任：（一）机动车之间发生交通事故的，由有过错的一方承担赔偿责任；双方都有过错的，按照各自过错的比例分担责任。（二）机动车与非机动车驾驶人、行人之间发生交通事故，非机动车驾驶人、行人没有过错的，由机动车一方承担赔偿责任；有证据证明非机动车驾驶人、行人有过错的，根据过错程度适当减轻机动车一方的赔偿责任；机动车一方没有过错的，承担不超过百分之十的赔偿责任。', '2026-03-08 14:19:01.300209', 404, 958, b'1', 10, '{\"keywords\":[\"第七十六条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"NORP\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"第七十六条\",\"type\":\"ARTICLE_REF\"}]}', 707, 'doc_404_seg_10', 'paragraph');
INSERT INTO `segments` VALUES (1614, '第四章 道路通行规定', '第九十一条 饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车的，处十日以下拘留，并处一千元以上二千元以下罚款，吊销机动车驾驶证。醉酒驾驶机动车的，由公安机关交通管理部门约束至酒醒，吊销机动车驾驶证，依法追究刑事责任；五年内不得重新取得机动车驾驶证。', '2026-03-08 14:19:01.300209', 404, 1120, b'1', 11, '{\"keywords\":[\"第九十一条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"MONEY\"],\"legal_entities\":[{\"text\":\"第九十一条\",\"type\":\"ARTICLE_REF\"}]}', 959, 'doc_404_seg_11', 'paragraph');
INSERT INTO `segments` VALUES (1615, '第四章 道路通行规定', '第九十九条 有下列行为之一的，由公安机关交通管理部门处二百元以上二千元以下罚款：（一）未取得机动车驾驶证、机动车驾驶证被吊销或者机动车驾驶证被暂扣期间驾驶机动车的；（二）将机动车交由未取得机动车驾驶证或者机动车驾驶证被吊销、暂扣的人驾驶的；（三）造成交通事故后逃逸，尚不构成犯罪的；（四）机动车行驶超过规定时速百分之五十的。', '2026-03-08 14:19:01.301617', 404, 1283, b'1', 12, '{\"keywords\":[\"尚不构成犯罪\",\"第九十九条\"],\"entity_labels\":[\"ORDINAL\",\"MONEY\",\"CARDINAL\",\"PERCENT\"],\"legal_entities\":[{\"text\":\"尚不构成犯罪\",\"type\":\"CRIME\"},{\"text\":\"第九十九条\",\"type\":\"ARTICLE_REF\"}]}', 1121, 'doc_404_seg_12', 'paragraph');
INSERT INTO `segments` VALUES (1616, '第一章 总则', '第一条 为维护社会治安秩序，保障公共安全，保护公民、法人和其他组织的合法权益，规范和保障公安机关及其人民警察依法履行治安管理职责，制定本法。', '2026-03-08 14:19:01.301617', 404, 1354, b'1', 13, '{\"keywords\":[\"第一条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一条\",\"type\":\"ARTICLE_REF\"}]}', 1284, 'doc_404_seg_13', 'paragraph');
INSERT INTO `segments` VALUES (1617, '第一章 总则', '第二条 扰乱公共秩序，妨害公共安全，侵犯人身权利、财产权利，妨害社会管理，具有社会危害性，依照《中华人民共和国刑法》的规定构成犯罪的，依法追究刑事责任；尚不够刑事处罚的，由公安机关依照本法给予治安管理处罚。', '2026-03-08 14:19:01.301617', 404, 1458, b'1', 14, '{\"keywords\":[\"的规定构成犯罪\",\"《中华人民共和国刑法》\",\"第二条\"],\"entity_labels\":[\"ORDINAL\",\"LAW\"],\"legal_entities\":[{\"text\":\"的规定构成犯罪\",\"type\":\"CRIME\"},{\"text\":\"《中华人民共和国刑法》\",\"type\":\"LAW_REF\"},{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 1355, 'doc_404_seg_14', 'paragraph');
INSERT INTO `segments` VALUES (1618, '第二章 处罚的种类和适用', '第十条 治安管理处罚的种类分为：（一）警告；（二）罚款；（三）行政拘留；（四）吊销公安机关发放的许可证。对违反治安管理的外国人，可以附加适用限期出境或者驱逐出境。', '2026-03-08 14:19:01.303065', 404, 1540, b'1', 15, '{\"keywords\":[\"第十条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第十条\",\"type\":\"ARTICLE_REF\"}]}', 1459, 'doc_404_seg_15', 'paragraph');
INSERT INTO `segments` VALUES (1619, '第二章 处罚的种类和适用', '第十二条 已满十四周岁不满十八周岁的人违反治安管理的，从轻或者减轻处罚；不满十四周岁的人违反治安管理的，不予处罚，但是应当责令其监护人严加管教。', '2026-03-08 14:19:01.303065', 404, 1613, b'1', 16, '{\"keywords\":[\"第十二条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"QUANTITY\"],\"legal_entities\":[{\"text\":\"第十二条\",\"type\":\"ARTICLE_REF\"}]}', 1541, 'doc_404_seg_16', 'paragraph');
INSERT INTO `segments` VALUES (1620, '第二章 处罚的种类和适用', '第十九条 违反治安管理有下列情形之一的，减轻处罚或者不予处罚：（一）情节特别轻微的；（二）主动消除或者减轻违法后果，并取得被侵害人谅解的；（三）出于他人胁迫或者诱骗的；（四）主动投案，向公安机关如实陈述自己的违法行为的；（五）有立功表现的。', '2026-03-08 14:19:01.303065', 404, 1734, b'1', 17, '{\"keywords\":[\"第十九条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第十九条\",\"type\":\"ARTICLE_REF\"}]}', 1614, 'doc_404_seg_17', 'paragraph');
INSERT INTO `segments` VALUES (1621, '第三章 违反治安管理的行为和处罚', '第二十三条 有下列行为之一的，处警告或者二百元以下罚款；情节较重的，处五日以上十日以下拘留，可以并处五百元以下罚款：（一）扰乱机关、团体、企业、事业单位秩序，致使工作、生产、营业、医疗、教学、科研不能正常进行，尚未造成严重损失的；（二）扰乱车站、港口、码头、机场、商场、公园、展览馆或者其他公共场所秩序的；（三）扰乱公共汽车、电车、火车、船舶、航空器或者其他公共交通工具上的秩序的。', '2026-03-08 14:19:01.304400', 404, 1926, b'1', 18, '{\"keywords\":[\"第二十三条\"],\"entity_labels\":[\"ORDINAL\",\"MONEY\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十三条\",\"type\":\"ARTICLE_REF\"}]}', 1735, 'doc_404_seg_18', 'paragraph');
INSERT INTO `segments` VALUES (1622, '第三章 违反治安管理的行为和处罚', '第四十二条 有下列行为之一的，处五日以下拘留或者五百元以下罚款；情节较重的，处五日以上十日以下拘留，可以并处五百元以下罚款：（一）写恐吓信或者以其他方法威胁他人人身安全的；（二）公然侮辱他人或者捏造事实诽谤他人的；（三）捏造事实诬告陷害他人，企图使他人受到刑事追究或者受到治安管理处罚的；（四）对证人及其近亲属进行威胁、侮辱、殴打或者打击报复的；（五）多次发送淫秽、侮辱、恐吓或者其他信息，干扰他人正常生活的；（六）偷窥、偷拍、窃听、散布他人隐私的。', '2026-03-08 14:19:01.304400', 404, 2152, b'1', 19, '{\"keywords\":[\"第四十二条\"],\"entity_labels\":[\"ORDINAL\",\"MONEY\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第四十二条\",\"type\":\"ARTICLE_REF\"}]}', 1927, 'doc_404_seg_19', 'paragraph');
INSERT INTO `segments` VALUES (1623, '第三章 违反治安管理的行为和处罚', '第四十三条 殴打他人的，或者故意伤害他人身体的，处五日以上十日以下拘留，并处二百元以上五百元以下罚款；情节较轻的，处五日以下拘留或者五百元以下罚款。有下列情形之一的，处十日以上十五日以下拘留，并处五百元以上一千元以下罚款：（一）结伙殴打、伤害他人的；（二）殴打、伤害残疾人、孕妇、不满十四周岁的人或者六十周岁以上的人的；（三）多次殴打、伤害他人或者一次殴打、伤害多人的。', '2026-03-08 14:19:01.304400', 404, 2338, b'1', 20, '{\"keywords\":[\"第四十三条\"],\"entity_labels\":[\"ORDINAL\",\"MONEY\",\"CARDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第四十三条\",\"type\":\"ARTICLE_REF\"}]}', 2153, 'doc_404_seg_20', 'paragraph');
INSERT INTO `segments` VALUES (1624, '第三章 违反治安管理的行为和处罚', '第四十九条 盗窃、诈骗、哄抢、抢夺、敲诈勒索或者故意损毁公私财物的，处五日以上十日以下拘留，可以并处五百元以下罚款；情节较重的，处十日以上十五日以下拘留，可以并处一千元以下罚款。', '2026-03-08 14:19:01.305737', 404, 2428, b'1', 21, '{\"keywords\":[\"第四十九条\"],\"entity_labels\":[\"ORDINAL\",\"MONEY\"],\"legal_entities\":[{\"text\":\"第四十九条\",\"type\":\"ARTICLE_REF\"}]}', 2339, 'doc_404_seg_21', 'paragraph');
INSERT INTO `segments` VALUES (1625, '第三章 违反治安管理的行为和处罚', '第七十二条 有下列行为之一的，处十日以上十五日以下拘留，可以并处二千元以下罚款；情节较轻的，处五日以下拘留或者五百元以下罚款：（一）非法持有鸦片不满二百克、海洛因或者甲基苯丙胺不满十克或者其他少量毒品的；（二）向他人提供毒品的；（三）吸食、注射毒品的；（四）胁迫、欺骗医务人员开具麻醉药品、精神药品的。', '2026-03-08 14:19:01.305737', 404, 2580, b'1', 22, '{\"keywords\":[\"第七十二条\"],\"entity_labels\":[\"ORDINAL\",\"MONEY\",\"QUANTITY\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第七十二条\",\"type\":\"ARTICLE_REF\"}]}', 2429, 'doc_404_seg_22', 'paragraph');
INSERT INTO `segments` VALUES (1626, '第二章 结婚', '第一千零四十条 本编调整因婚姻家庭产生的民事关系。\n第一千零四十一条 婚姻家庭受国家保护。实行婚姻自由、一夫一妻、男女平等的婚姻制度。保护妇女、未成年人、老年人、残疾人的合法权益。\n第一千零四十二条 禁止包办、买卖婚姻和其他干涉婚姻自由的行为。禁止借婚姻索取财物。禁止重婚。禁止有配偶者与他人同居。禁止家庭暴力。禁止家庭成员间的虐待和遗弃。', '2026-03-08 14:19:02.678333', 403, 217, b'1', 0, '{\"keywords\":[\"第一千零四十条\",\"第一千零四十一条\",\"第一千零四十二条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千零四十条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零四十一条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零四十二条\",\"type\":\"ARTICLE_REF\"}]}', 47, 'doc_403_seg_0', 'semantic');
INSERT INTO `segments` VALUES (1627, '第三章 家庭关系', '第二章 结婚\n第一千零四十六条 结婚应当男女双方完全自愿，禁止任何一方对另一方加以强迫，禁止任何组织或者个人加以干涉。\n第一千零四十七条 结婚年龄，男不得早于二十二周岁，女不得早于二十周岁。\n第一千零四十八条 直系血亲或者三代以内的旁系血亲禁止结婚。\n第一千零四十九条 要求结婚的男女双方应当亲自到婚姻登记机关申请结婚登记。符合本法规定的，予以登记，发给结婚证。完成结婚登记，即确立婚姻关系。未办理结婚登记的，应当补办登记。\n第一千零五十一条 有下列情形之一的，婚姻无效：（一）重婚；（二）有禁止结婚的亲属关系；（三）未到法定婚龄。', '2026-03-08 14:19:02.683662', 403, 484, b'1', 1, '{\"keywords\":[\"第一千零四十六条\",\"第一千零四十七条\",\"第一千零四十八条\",\"第一千零四十九条\",\"第一千零五十一条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"DATE\"],\"legal_entities\":[{\"text\":\"第一千零四十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零四十七条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零四十八条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零四十九条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零五十一条\",\"type\":\"ARTICLE_REF\"}]}', 218, 'doc_403_seg_1', 'semantic');
INSERT INTO `segments` VALUES (1628, '第四章 离婚', '第一千零五十五条 夫妻在婚姻家庭中地位平等。\n第一千零五十八条 夫妻双方平等享有对未成年子女抚养、教育和保护的权利，共同承担对未成年子女抚养、教育和保护的义务。\n第一千零六十二条 夫妻在婚姻关系存续期间所得的下列财产，为夫妻的共同财产，归夫妻共同所有：（一）工资、奖金、劳务报酬；（二）生产、经营、投资的收益；（三）知识产权的收益；（四）继承或者受赠的财产，但是本法第一千零六十三条第三项规定的除外；（五）其他应当归共同所有的财产。夫妻对共同财产，有平等的处理权。\n第一千零六十三条 下列财产为夫妻一方的个人财产：（一）一方的婚前财产；（二）一方因受到人身损害获得的赔偿或者补偿；（三）遗嘱或者赠与合同中确定只归一方的财产；（四）一方专用的生活用品；（五）其他应当归一方的财产。\n第一千零六十七条 父母不履行抚养义务的，未成年子女或者不能独立生活的成年子女，有要求父母给付抚养费的权利。成年子女不履行赡养义务的，缺乏劳动能力或者生活困难的父母，有要求成年子女给付赡养费的权利。', '2026-03-08 14:19:02.684928', 403, 932, b'1', 2, '{\"keywords\":[\"第一千零五十五条\",\"第一千零五十八条\",\"第一千零六十二条\",\"第一千零六十三条\",\"第一千零六十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千零五十五条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零五十八条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零六十二条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零六十三条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零六十七条\",\"type\":\"ARTICLE_REF\"}]}', 494, 'doc_403_seg_2', 'semantic');
INSERT INTO `segments` VALUES (1629, '第四章 离婚', '第四章 离婚\n第一千零七十六条 夫妻双方自愿离婚的，应当签订书面离婚协议，并亲自到婚姻登记机关申请离婚登记。离婚协议应当载明双方自愿离婚的意思表示和对子女抚养、财产以及债务处理等事项协商一致的意见。\n第一千零七十七条 自婚姻登记机关收到离婚登记申请之日起三十日内，任何一方不愿意离婚的，可以向婚姻登记机关撤回离婚登记申请。前款规定期限届满后三十日内，双方应当亲自到婚姻登记机关申请发给离婚证；未申请的，视为撤回离婚登记申请。\n第一千零七十九条 夫妻一方要求离婚的，可以由有关组织进行调解或者直接向人民法院提起离婚诉讼。人民法院审理离婚案件，应当进行调解；如果感情确已破裂，调解无效的，应当准予离婚。有下列情形之一，调解无效的，应当准予离婚：（一）重婚或者与他人同居；（二）实施家庭暴力或者虐待、遗弃家庭成员；（三）有赌博、吸毒等恶习屡教不改；（四）因感情不和分居满二年；（五）其他导致夫妻感情破裂的情形。\n第一千零八十四条 父母与子女间的关系，不因父母离婚而消除。离婚后，子女无论由父或者母直接抚养，仍是父母双方的子女。离婚后，父母对于子女仍有抚养、教育、保护的权利和义务。离婚后，不满两周岁的子女，以由母亲直接抚养为原则。已满两周岁的子女，父母双方对抚养问题协议不成的，由人民法院根据双方的具体情况，按照最有利于未成年子女的原则判决。子女已满八周岁的，应当尊重其真实意愿。\n第一千零八十七条 离婚时，夫妻的共同财产由双方协议处理；协议不成的，由人民法院根据财产的具体情况，按照照顾子女、女方和无过错方权益的原则判决。\n第一千零九十一条 有下列情形之一，导致离婚的，无过错方有权请求损害赔偿：（一）重婚；（二）与他人同居；（三）实施家庭暴力；（四）虐待、遗弃家庭成员；（五）有其他重大过错。', '2026-03-08 14:19:02.684928', 403, 1678, b'1', 3, '{\"keywords\":[\"第一千零七十六条\",\"第一千零七十七条\",\"第一千零七十九条\",\"第一千零八十四条\",\"第一千零八十七条\",\"第一千零九十一条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"ORG\",\"DATE\"],\"legal_entities\":[{\"text\":\"第一千零七十六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零七十七条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零七十九条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零八十四条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零八十七条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第一千零九十一条\",\"type\":\"ARTICLE_REF\"}]}', 933, 'doc_403_seg_3', 'semantic');
INSERT INTO `segments` VALUES (1630, '第一章 一般规定', '第一千一百二十一条 继承从被继承人死亡时开始。相互有继承关系的数人在同一事件中死亡，难以确定死亡时间的，推定没有其他继承人的人先死亡。都有其他继承人，辈份不同的，推定长辈先死亡；辈份相同的，推定同时死亡，相互不发生继承。', '2026-03-08 14:19:02.684928', 403, 1855, b'1', 4, '{\"keywords\":[\"第一千一百二十一条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百二十一条\",\"type\":\"ARTICLE_REF\"}]}', 1745, 'doc_403_seg_4', 'semantic');
INSERT INTO `segments` VALUES (1631, '第二章 法定继承', '第一千一百二十二条 遗产是自然人死亡时遗留的个人合法财产。依照法律规定或者根据其性质不得继承的遗产，不得继承。', '2026-03-08 14:19:02.685927', 403, 1911, b'1', 5, '{\"keywords\":[\"第一千一百二十二条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百二十二条\",\"type\":\"ARTICLE_REF\"}]}', 1856, 'doc_403_seg_5', 'semantic');
INSERT INTO `segments` VALUES (1632, '第二章 法定继承', '第一千一百二十七条 遗产按照下列顺序继承：（一）第一顺序：配偶、子女、父母；（二）第二顺序：兄弟姐妹、祖父母、外祖父母。继承开始后，由第一顺序继承人继承，第二顺序继承人不继承；没有第一顺序继承人继承的，由第二顺序继承人继承。', '2026-03-08 14:19:02.685927', 403, 2052, b'1', 6, '{\"keywords\":[\"第一千一百二十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百二十七条\",\"type\":\"ARTICLE_REF\"}]}', 1940, 'doc_403_seg_6', 'semantic');
INSERT INTO `segments` VALUES (1633, '第二章 法定继承', '第一千一百二十八条 被继承人的子女先于被继承人死亡的，由被继承人的子女的直系晚辈血亲代位继承。被继承人的兄弟姐妹先于被继承人死亡的，由被继承人的兄弟姐妹的子女代位继承。代位继承人一般只能继承被代位继承人有权继承的遗产份额。', '2026-03-08 14:19:02.686927', 403, 2164, b'1', 7, '{\"keywords\":[\"第一千一百二十八条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百二十八条\",\"type\":\"ARTICLE_REF\"}]}', 2053, 'doc_403_seg_7', 'semantic');
INSERT INTO `segments` VALUES (1634, '第三章 遗嘱继承和遗赠', '第一千一百三十条 同一顺序继承人继承遗产的份额，一般应当均等。对生活有特殊困难又缺乏劳动能力的继承人，分配遗产时，应当予以照顾。对被继承人尽了主要扶养义务或者与被继承人共同生活的继承人，分配遗产时，可以多分。有扶养能力和有扶养条件的继承人，不尽扶养义务的，分配遗产时，应当不分或者少分。', '2026-03-08 14:19:02.686927', 403, 2308, b'1', 8, '{\"keywords\":[\"第一千一百三十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百三十条\",\"type\":\"ARTICLE_REF\"}]}', 2165, 'doc_403_seg_8', 'semantic');
INSERT INTO `segments` VALUES (1635, '第三章 遗嘱继承和遗赠', '第一千一百三十三条 自然人可以依照本法规定立遗嘱处分个人财产，并可以指定遗嘱执行人。自然人可以立遗嘱将个人财产指定由法定继承人中的一人或者数人继承。自然人可以立遗嘱将个人财产赠与国家、集体或者法定继承人以外的组织、个人。', '2026-03-08 14:19:02.687928', 403, 2431, b'1', 9, '{\"keywords\":[\"第一千一百三十三条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百三十三条\",\"type\":\"ARTICLE_REF\"}]}', 2321, 'doc_403_seg_9', 'semantic');
INSERT INTO `segments` VALUES (1636, '第三章 遗嘱继承和遗赠', '第一千一百三十五条 代书遗嘱应当有两个以上见证人在场见证，由其中一人代书，并由遗嘱人、代书人和其他见证人签名，注明年、月、日。', '2026-03-08 14:19:02.687928', 403, 2530, b'1', 10, '{\"keywords\":[\"第一千一百三十五条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"PERSON\",\"DATE\"],\"legal_entities\":[{\"text\":\"第一千一百三十五条\",\"type\":\"ARTICLE_REF\"}]}', 2467, 'doc_403_seg_10', 'semantic');
INSERT INTO `segments` VALUES (1637, '第三章 遗嘱继承和遗赠', '第一千一百三十六条 打印遗嘱应当有两个以上见证人在场见证。遗嘱人和见证人应当在遗嘱每一页签名，注明年、月、日。', '2026-03-08 14:19:02.687928', 403, 2586, b'1', 11, '{\"keywords\":[\"第一千一百三十六条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"PERSON\",\"DATE\"],\"legal_entities\":[{\"text\":\"第一千一百三十六条\",\"type\":\"ARTICLE_REF\"}]}', 2531, 'doc_403_seg_11', 'semantic');
INSERT INTO `segments` VALUES (1638, '第三章 遗嘱继承和遗赠', '第一千一百三十七条 以录音录像形式立的遗嘱，应当有两个以上见证人在场见证。遗嘱人和见证人应当在录音录像中记录其姓名或者肖像，以及年、月、日。', '2026-03-08 14:19:02.688927', 403, 2657, b'1', 12, '{\"keywords\":[\"第一千一百三十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"PERSON\",\"DATE\"],\"legal_entities\":[{\"text\":\"第一千一百三十七条\",\"type\":\"ARTICLE_REF\"}]}', 2587, 'doc_403_seg_12', 'semantic');
INSERT INTO `segments` VALUES (1639, '第三章 遗嘱继承和遗赠', '第一千一百四十二条 遗嘱人可以撤回、变更自己所立的遗嘱。立遗嘱后，遗嘱人实施与遗嘱内容相反的民事法律行为的，视为对遗嘱相关内容的撤回。立有数份遗嘱，内容相抵触的，以最后的遗嘱为准。', '2026-03-08 14:19:02.688927', 403, 2748, b'1', 13, '{\"keywords\":[\"第一千一百四十二条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第一千一百四十二条\",\"type\":\"ARTICLE_REF\"}]}', 2658, 'doc_403_seg_13', 'semantic');
INSERT INTO `segments` VALUES (1640, '第一章 通则', '第四百六十四条 合同是民事主体之间设立、变更、终止民事法律关系的协议。婚姻、收养、监护等有关身份关系的协议，适用有关该身份关系的法律规定；没有规定的，可以根据其性质参照适用本编规定。', '2026-03-08 14:19:03.576938', 402, 91, b'1', 0, '{\"keywords\":[\"第四百六十四条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四百六十四条\",\"type\":\"ARTICLE_REF\"}]}', 0, 'doc_402_seg_0', 'rule');
INSERT INTO `segments` VALUES (1641, '第二章 合同的订立', '第四百六十五条 依法成立的合同，受法律保护。依法成立的合同，仅对当事人具有法律约束力，但是法律另有规定的除外。', '2026-03-08 14:19:03.578938', 402, 146, b'1', 1, '{\"keywords\":[\"第四百六十五条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四百六十五条\",\"type\":\"ARTICLE_REF\"}]}', 91, 'doc_402_seg_1', 'rule');
INSERT INTO `segments` VALUES (1642, '第二章 合同的订立', '第四百七十二条 要约是希望与他人订立合同的意思表示，该意思表示应当符合下列条件：（一）内容具体确定；（二）表明经受要约人承诺，要约人即受该意思表示约束。', '2026-03-08 14:19:03.579938', 402, 222, b'1', 2, '{\"keywords\":[\"第四百七十二条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第四百七十二条\",\"type\":\"ARTICLE_REF\"}]}', 146, 'doc_402_seg_2', 'rule');
INSERT INTO `segments` VALUES (1643, '第二章 合同的订立', '第四百九十条 当事人采用合同书形式订立合同的，自当事人均签名、盖章或者按指印时合同成立。在签名、盖章或者按指印之前，当事人一方已经履行主要义务，对方接受时，该合同成立。', '2026-03-08 14:19:03.579938', 402, 306, b'1', 3, '{\"keywords\":[\"第四百九十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四百九十条\",\"type\":\"ARTICLE_REF\"}]}', 222, 'doc_402_seg_3', 'rule');
INSERT INTO `segments` VALUES (1644, '第二章 合同的订立', '第四百九十六条 格式条款是当事人为了重复使用而预先拟定，并在订立合同时未与对方协商的条款。采用格式条款订立合同的，提供格式条款的一方应当遵循公平原则确定当事人之间的权利和义务，并采取合理的方式提示对方注意免除或者减轻其责任等与对方有重大利害关系的条款，按照对方的要求，对该条款予以说明。', '2026-03-08 14:19:03.580937', 402, 449, b'1', 4, '{\"keywords\":[\"第四百九十六条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第四百九十六条\",\"type\":\"ARTICLE_REF\"}]}', 306, 'doc_402_seg_4', 'rule');
INSERT INTO `segments` VALUES (1645, '第四章 合同的履行', '第四百九十七条 有下列情形之一的，该格式条款无效：（一）具有本法第一编第六章第三节和本法第五百零六条规定的无效情形；（二）提供格式条款一方不合理地免除或者减轻其责任、加重对方责任、限制对方主要权利；（三）提供格式条款一方排除对方主要权利。\n第五百零二条 依法成立的合同，自成立时生效，但是法律另有规定或者当事人另有约定的除外。\n第五百零六条 合同中的下列免责条款无效：（一）造成对方人身损害的；（二）因故意或者重大过失造成对方财产损失的。\n第五百零九条 当事人应当按照约定全面履行自己的义务。当事人应当遵循诚信原则，根据合同的性质、目的和交易习惯履行通知、协助、保密等义务。', '2026-03-08 14:19:03.580937', 402, 736, b'1', 5, '{\"keywords\":[\"第四百九十七条\",\"第五百零六条\",\"第五百零二条\",\"第五百零九条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第四百九十七条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第五百零六条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第五百零二条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第五百零九条\",\"type\":\"ARTICLE_REF\"}]}', 449, 'doc_402_seg_5', 'rule');
INSERT INTO `segments` VALUES (1646, '第五章 合同的变更和转让', '第五百一十条 合同生效后，当事人就质量、价款或者报酬、履行地点等内容没有约定或者约定不明确的，可以协议补充；不能达成补充协议的，按照合同相关条款或者交易习惯确定。', '2026-03-08 14:19:03.581937', 402, 817, b'1', 6, '{\"keywords\":[\"第五百一十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百一十条\",\"type\":\"ARTICLE_REF\"}]}', 736, 'doc_402_seg_6', 'rule');
INSERT INTO `segments` VALUES (1647, '第六章 合同的权利义务终止', '第五百四十五条 债权人可以将债权的全部或者部分转让给第三人，但是有下列情形之一的除外：（一）根据债权性质不得转让；（二）按照当事人约定不得转让；（三）依照法律规定不得转让。', '2026-03-08 14:19:03.581937', 402, 903, b'1', 7, '{\"keywords\":[\"第五百四十五条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第五百四十五条\",\"type\":\"ARTICLE_REF\"}]}', 817, 'doc_402_seg_7', 'rule');
INSERT INTO `segments` VALUES (1648, '第六章 合同的权利义务终止', '第五百五十七条 有下列情形之一的，债权债务终止：（一）债务已经履行；（二）债务相互抵销；（三）债务人依法将标的物提存；（四）债权人免除债务；（五）债权债务同归于一人；（六）法律规定或者当事人约定终止的其他情形。', '2026-03-08 14:19:03.581937', 402, 1008, b'1', 8, '{\"keywords\":[\"第五百五十七条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第五百五十七条\",\"type\":\"ARTICLE_REF\"}]}', 903, 'doc_402_seg_8', 'rule');
INSERT INTO `segments` VALUES (1649, '第六章 合同的权利义务终止', '第五百六十二条 当事人协商一致，可以解除合同。当事人可以约定一方解除合同的事由。解除合同的事由发生时，解除权人可以解除合同。', '2026-03-08 14:19:03.582939', 402, 1070, b'1', 9, '{\"keywords\":[\"第五百六十二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百六十二条\",\"type\":\"ARTICLE_REF\"}]}', 1008, 'doc_402_seg_9', 'rule');
INSERT INTO `segments` VALUES (1650, '第七章 违约责任', '第五百六十三条 有下列情形之一的，当事人可以解除合同：（一）因不可抗力致使不能实现合同目的；（二）在履行期限届满前，当事人一方明确表示或者以自己的行为表明不履行主要债务；（三）当事人一方迟延履行主要债务，经催告后在合理期限内仍未履行；（四）当事人一方迟延履行债务或者有其他违约行为致使不能实现合同目的；（五）法律规定的其他情形。', '2026-03-08 14:19:03.582939', 402, 1234, b'1', 10, '{\"keywords\":[\"第五百六十三条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第五百六十三条\",\"type\":\"ARTICLE_REF\"}]}', 1070, 'doc_402_seg_10', 'rule');
INSERT INTO `segments` VALUES (1651, '第七章 违约责任', '第五百七十七条 当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担继续履行、采取补救措施或者赔偿损失等违约责任。', '2026-03-08 14:19:03.582939', 402, 1296, b'1', 11, '{\"keywords\":[\"第五百七十七条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百七十七条\",\"type\":\"ARTICLE_REF\"}]}', 1234, 'doc_402_seg_11', 'rule');
INSERT INTO `segments` VALUES (1652, '第七章 违约责任', '第五百七十八条 当事人一方明确表示或者以自己的行为表明不履行合同义务的，对方可以在履行期限届满前请求其承担违约责任。', '2026-03-08 14:19:03.583938', 402, 1354, b'1', 12, '{\"keywords\":[\"第五百七十八条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百七十八条\",\"type\":\"ARTICLE_REF\"}]}', 1296, 'doc_402_seg_12', 'rule');
INSERT INTO `segments` VALUES (1653, '第七章 违约责任', '第五百八十四条 当事人一方不履行合同义务或者履行合同义务不符合约定，造成对方损失的，损失赔偿额应当相当于因违约所造成的损失，包括合同履行后可以获得的利益；但是，不得超过违约一方订立合同时预见到或者应当预见到的因违约可能造成的损失。', '2026-03-08 14:19:03.583938', 402, 1469, b'1', 13, '{\"keywords\":[\"第五百八十四条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百八十四条\",\"type\":\"ARTICLE_REF\"}]}', 1354, 'doc_402_seg_13', 'rule');
INSERT INTO `segments` VALUES (1654, '第七章 违约责任', '第五百八十五条 当事人可以约定一方违约时应当根据违约情况向对方支付一定数额的违约金，也可以约定因违约产生的损失赔偿额的计算方法。约定的违约金低于造成的损失的，人民法院或者仲裁机构可以根据当事人的请求予以增加；约定的违约金过分高于造成的损失的，人民法院或者仲裁机构可以根据当事人的请求予以适当减少。', '2026-03-08 14:19:03.584938', 402, 1617, b'1', 14, '{\"keywords\":[\"第五百八十五条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百八十五条\",\"type\":\"ARTICLE_REF\"}]}', 1469, 'doc_402_seg_14', 'rule');
INSERT INTO `segments` VALUES (1655, '第一章 总则', '第五百九十条 当事人一方因不可抗力不能履行合同的，根据不可抗力的影响，部分或者全部免除责任，但是法律另有规定的除外。因不可抗力不能履行合同的，应当及时通知对方，以减轻可能给对方造成的损失，并应当在合理期限内提供证明。\n第二部分 消费者权益保护法', '2026-03-08 14:19:03.584938', 402, 1739, b'1', 15, '{\"keywords\":[\"第五百九十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第五百九十条\",\"type\":\"ARTICLE_REF\"}]}', 1617, 'doc_402_seg_15', 'rule');
INSERT INTO `segments` VALUES (1656, '第二章 消费者的权利', '第二条 消费者为生活消费需要购买、使用商品或者接受服务，其权益受本法保护；本法未作规定的，受其他有关法律、法规保护。', '2026-03-08 14:19:03.584938', 402, 1797, b'1', 16, '{\"keywords\":[\"第二条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二条\",\"type\":\"ARTICLE_REF\"}]}', 1739, 'doc_402_seg_16', 'rule');
INSERT INTO `segments` VALUES (1657, '第二章 消费者的权利', '第七条 消费者在购买、使用商品和接受服务时享有人身、财产安全不受损害的权利。消费者有权要求经营者提供的商品和服务，符合保障人身、财产安全的要求。', '2026-03-08 14:19:03.585939', 402, 1869, b'1', 17, '{\"keywords\":[\"第七条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第七条\",\"type\":\"ARTICLE_REF\"}]}', 1797, 'doc_402_seg_17', 'rule');
INSERT INTO `segments` VALUES (1658, '第二章 消费者的权利', '第八条 消费者享有知悉其购买、使用的商品或者接受的服务的真实情况的权利。消费者有权根据商品或者服务的不同情况，要求经营者提供商品的价格、产地、生产者、用途、性能、规格、等级、主要成份、生产日期、有效期限、检验合格证明、使用方法说明书、售后服务，或者服务的内容、规格、费用等有关情况。', '2026-03-08 14:19:03.585939', 402, 2010, b'1', 18, '{\"keywords\":[\"第八条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第八条\",\"type\":\"ARTICLE_REF\"}]}', 1869, 'doc_402_seg_18', 'rule');
INSERT INTO `segments` VALUES (1659, '第二章 消费者的权利', '第九条 消费者享有自主选择商品或者服务的权利。消费者有权自主选择提供商品或者服务的经营者，自主选择商品品种或者服务方式，自主决定购买或者不购买任何一种商品、接受或者不接受任何一项服务。', '2026-03-08 14:19:03.585939', 402, 2102, b'1', 19, '{\"keywords\":[\"第九条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第九条\",\"type\":\"ARTICLE_REF\"}]}', 2010, 'doc_402_seg_19', 'rule');
INSERT INTO `segments` VALUES (1660, '第二章 消费者的权利', '第十条 消费者享有公平交易的权利。消费者在购买商品或者接受服务时，有权获得质量保障、价格合理、计量正确等公平交易条件，有权拒绝经营者的强制交易行为。', '2026-03-08 14:19:03.586937', 402, 2176, b'1', 20, '{\"keywords\":[\"第十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十条\",\"type\":\"ARTICLE_REF\"}]}', 2102, 'doc_402_seg_20', 'rule');
INSERT INTO `segments` VALUES (1661, '第三章 经营者的义务', '第十六条 经营者向消费者提供商品或者服务，应当依照本法和其他有关法律、法规的规定履行义务。经营者和消费者有约定的，应当按照约定履行义务，但双方的约定不得违背法律、法规的规定。', '2026-03-08 14:19:03.586937', 402, 2263, b'1', 21, '{\"keywords\":[\"第十六条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十六条\",\"type\":\"ARTICLE_REF\"}]}', 2176, 'doc_402_seg_21', 'rule');
INSERT INTO `segments` VALUES (1662, '第三章 经营者的义务', '第十八条 经营者应当保证其提供的商品或者服务符合保障人身、财产安全的要求。对可能危及人身、财产安全的商品和服务，应当向消费者作出真实的说明和明确的警示，并说明和标明正确使用商品或者接受服务的方法以及防止危害发生的方法。', '2026-03-08 14:19:03.586937', 402, 2372, b'1', 22, '{\"keywords\":[\"第十八条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第十八条\",\"type\":\"ARTICLE_REF\"}]}', 2263, 'doc_402_seg_22', 'rule');
INSERT INTO `segments` VALUES (1663, '第三章 经营者的义务', '第二十条 经营者向消费者提供有关商品或者服务的质量、性能、用途、有效期限等信息，应当真实、全面，不得作虚假或者引人误解的宣传。', '2026-03-08 14:19:03.587938', 402, 2435, b'1', 23, '{\"keywords\":[\"第二十条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十条\",\"type\":\"ARTICLE_REF\"}]}', 2372, 'doc_402_seg_23', 'rule');
INSERT INTO `segments` VALUES (1664, '第三章 经营者的义务', '第二十三条 经营者应当保证在正常使用商品或者接受服务的情况下其提供的商品或者服务应当具有的质量、性能、用途和有效期限；但消费者在购买该商品或者接受该服务前已经知道其存在瑕疵，且存在该瑕疵不违反法律强制性规定的除外。', '2026-03-08 14:19:03.587938', 402, 2542, b'1', 24, '{\"keywords\":[\"第二十三条\"],\"entity_labels\":[\"ORDINAL\"],\"legal_entities\":[{\"text\":\"第二十三条\",\"type\":\"ARTICLE_REF\"}]}', 2435, 'doc_402_seg_24', 'rule');
INSERT INTO `segments` VALUES (1665, '第四章 国家对消费者合法权益的保护', '第二十五条 经营者采用网络、电视、电话、邮购等方式销售商品，消费者有权自收到商品之日起七日内退货，且无需说明理由，但下列商品除外：（一）消费者定作的；（二）鲜活易腐的；（三）在线下载或者消费者拆封的音像制品、计算机软件等数字化商品；（四）交付的报纸、期刊。', '2026-03-08 14:19:03.587938', 402, 2670, b'1', 25, '{\"keywords\":[\"第二十五条\"],\"entity_labels\":[\"ORDINAL\",\"DATE\",\"CARDINAL\"],\"legal_entities\":[{\"text\":\"第二十五条\",\"type\":\"ARTICLE_REF\"}]}', 2542, 'doc_402_seg_25', 'rule');
INSERT INTO `segments` VALUES (1666, '第五章 法律责任', '第三十九条 消费者和经营者发生消费者权益争议的，可以通过下列途径解决：（一）与经营者协商和解；（二）请求消费者协会或者依法成立的其他调解组织调解；（三）向有关行政部门投诉；（四）根据与经营者达成的仲裁协议提请仲裁机构仲裁；（五）向人民法院提起诉讼。', '2026-03-08 14:19:03.588938', 402, 2794, b'1', 26, '{\"keywords\":[\"第三十九条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"ORG\"],\"legal_entities\":[{\"text\":\"第三十九条\",\"type\":\"ARTICLE_REF\"}]}', 2670, 'doc_402_seg_26', 'rule');
INSERT INTO `segments` VALUES (1667, '第五章 法律责任', '第五十五条 经营者提供商品或者服务有欺诈行为的，应当按照消费者的要求增加赔偿其受到的损失，增加赔偿的金额为消费者购买商品的价款或者接受服务的费用的三倍；增加赔偿的金额不足五百元的，为五百元。法律另有规定的，依照其规定。\n经营者明知商品或者服务存在缺陷，仍然向消费者提供，造成消费者或者其他受害人死亡或者健康严重损害的，受害人有权要求经营者依照本法第四十九条、第五十一条等法律规定赔偿损失，并有权要求所受损失二倍以下的惩罚性赔偿。', '2026-03-08 14:19:03.588938', 402, 3008, b'1', 27, '{\"keywords\":[\"第五十五条\",\"第四十九条\",\"第五十一条\"],\"entity_labels\":[\"ORDINAL\",\"CARDINAL\",\"MONEY\"],\"legal_entities\":[{\"text\":\"第五十五条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第四十九条\",\"type\":\"ARTICLE_REF\"},{\"text\":\"第五十一条\",\"type\":\"ARTICLE_REF\"}]}', 2794, 'doc_402_seg_27', 'rule');
